final_template:
variable "domain_name" {
  description = "The domain name for the Route 53 hosted zone"
  type        = string
  default     = "example.com"
}

variable "ipv4_address" {
  description = "The IPv4 address to map the domain to"
  type        = string
  default     = "192.0.2.1"
}

resource "aws_route53_zone" "main" {
  name = var.domain_name
}

resource "aws_route53_record" "apex" {
  zone_id = aws_route53_zone.main.zone_id
  name    = ""
  type    = "A"
  ttl     = 300
  records = [var.ipv4_address]
}

variable "domain_name" {
  description = "The domain name for which to create the Route 53 hosted zone and AAAA record"
  type        = string
  default     = "example.com"
}

variable "ipv6_address" {
  description = "The IPv6 address to map the domain name to"
  type        = string
  default     = "2001:db8::1"
}

resource "aws_route53_zone" "main" {
  name = var.domain_name

  lifecycle {
    prevent_destroy = true
  }
}

resource "aws_route53_record" "ipv6" {
  zone_id = aws_route53_zone.main.zone_id
  name    = var.domain_name
  type    = "AAAA"
  ttl     = 300
  records = [var.ipv6_address]
}

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

resource "aws_route53_zone" "example_zone" {
  name = "example"
}

resource "aws_route53_record" "txt_verification" {
  zone_id = aws_route53_zone.example_zone.zone_id
  name    = ""
  type    = "TXT"
  ttl     = 300
  records = ["\"passwordpassword\""]
}

terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

variable "environment_name" {
  description = "Name of the Elastic Beanstalk environment"
  type        = string
  default     = "production"
}

data "aws_availability_zones" "available" {
  state = "available"
}

data "aws_caller_identity" "current" {}

# --------------------------------------------------------------------------
# Elastic Beanstalk Application
# --------------------------------------------------------------------------
resource "aws_elastic_beanstalk_application" "my_app" {
  name        = "my-app"
  description = "My Elastic Beanstalk application"

  tags = {
    Name           = "my-app"
    Environment    = var.environment_name
    ManagedBy      = "Terraform"
  }
}

# --------------------------------------------------------------------------
# IAM Roles and Instance Profile
# --------------------------------------------------------------------------
resource "aws_iam_role" "eb_service_role" {
  name               = "eb-service-role"
  assume_role_policy = jsonencode({
    Version   = "2012-10-17"
    Statement = [
      {
        Effect    = "Allow"
        Principal = {
          Service = "elasticbeanstalk.amazonaws.com"
        }
        Action    = "sts:AssumeRole"
      }
    ]
  })

  tags = {
    Name      = "eb-service-role"
    ManagedBy = "Terraform"
  }
}

resource "aws_iam_role_policy_attachment" "eb_service_policy" {
  role       = aws_iam_role.eb_service_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSElasticBeanstalkService"
}

resource "aws_iam_role" "eb_instance_profile_role" {
  name               = "eb-instance-profile-role"
  assume_role_policy = jsonencode({
    Version   = "2012-10-17"
    Statement = [
      {
        Effect    = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
        Action    = "sts:AssumeRole"
      }
    ]
  })

  tags = {
    Name      = "eb-instance-profile-role"
    ManagedBy = "Terraform"
  }
}

resource "aws_iam_role_policy_attachment" "eb_web_tier_policy" {
  role       = aws_iam_role.eb_instance_profile_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

resource "aws_iam_instance_profile" "eb_instance_profile" {
  name = "eb-instance-profile"
  role = aws_iam_role.eb_instance_profile_role.name

  tags = {
    Name      = "eb-instance-profile"
    ManagedBy = "Terraform"
  }
}

# --------------------------------------------------------------------------
# Networking: VPC, Internet Gateway, Subnets, Route Table
# --------------------------------------------------------------------------
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name      = "eb-vpc"
    ManagedBy = "Terraform"
  }
}

resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name      = "eb-igw"
    ManagedBy = "Terraform"
  }
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }

  tags = {
    Name      = "eb-public-rt"
    ManagedBy = "Terraform"
  }
}

resource "aws_subnet" "public" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name      = "eb-public-subnet-${count.index + 1}"
    ManagedBy = "Terraform"
  }
}

resource "aws_route_table_association" "public" {
  count          = 2
  subnet_id      = aws_subnet.public[count.index].id
  route_table_id = aws_route_table.public.id
}

# --------------------------------------------------------------------------
# Security Group for Elastic Beanstalk (no explicit egress rules)
# --------------------------------------------------------------------------
resource "aws_security_group" "eb_sg" {
  name        = "eb-security-group"
  description = "Security group for Elastic Beanstalk environment"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name      = "eb-security-group"
    ManagedBy = "Terraform"
  }
}

# --------------------------------------------------------------------------
# KMS Customer Managed Key for S3 Bucket Encryption
# --------------------------------------------------------------------------
resource "aws_kms_key" "app_versions" {
  description             = "KMS CMK for my-app-versions S3 bucket"
  deletion_window_in_days = 7
  enable_key_rotation     = true

  tags = {
    Name      = "my-app-versions-key"
    ManagedBy = "Terraform"
  }
}

# --------------------------------------------------------------------------
# S3 Bucket for Application Source Bundles
# --------------------------------------------------------------------------
resource "aws_s3_bucket" "app_versions" {
  bucket        = "my-app-versions-${data.aws_caller_identity.current.account_id}"
  force_destroy = false

  lifecycle {
    prevent_destroy = true
  }

  tags = {
    Name      = "my-app-versions"
    ManagedBy = "Terraform"
  }
}

resource "aws_s3_bucket_versioning" "app_versions" {
  bucket = aws_s3_bucket.app_versions.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "app_versions" {
  bucket = aws_s3_bucket.app_versions.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm     = "aws:kms"
      kms_master_key_id = aws_kms_key.app_versions.arn
    }
    bucket_key_enabled = true
  }
}

resource "aws_s3_bucket_public_access_block" "app_versions" {
  bucket = aws_s3_bucket.app_versions.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_s3_bucket_lifecycle_configuration" "app_versions" {
  bucket = aws_s3_bucket.app_versions.id

  rule {
    id     = "expire-old-versions"
    status = "Enabled"
    filter {}
    noncurrent_version_expiration {
      noncurrent_days = 30
    }
  }
}

terraform {
  required_version = ">= 1.3"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = ">= 5.0, < 6.0"
    }
  }
}

variable "environment" {
  default     = "dev"
  description = "Deployment environment tag"
  type        = string
}

variable "tags" {
  default = {
    Terraform   = "true"
    Environment = "dev"
  }
  description = "Common tags for all resources"
  type        = map(string)
}

locals {
  app_name     = "go-app"
  app_port     = 8080
  cidr_block   = "10.0.0.0/16"
  region       = data.aws_region.current.id
  account_id   = data.aws_caller_identity.current.account_id
}

data "aws_availability_zones" "available" {
  state = "available"
}

data "aws_region" "current" {}

data "aws_caller_identity" "current" {}

# VPC
resource "aws_vpc" "main" {
  cidr_block           = local.cidr_block
  enable_dns_hostnames = true
  enable_dns_support   = true
  tags = merge(var.tags, {
    Name = "${local.app_name}-vpc-${var.environment}"
  })
}

# Internet Gateway
resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id
  tags = merge(var.tags, {
    Name = "${local.app_name}-igw-${var.environment}"
  })
}

# Public subnets (one per AZ)
resource "aws_subnet" "public" {
  count             = length(data.aws_availability_zones.available.names)
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(local.cidr_block, 8, count.index)
  availability_zone = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false
  tags = merge(var.tags, {
    Name = "${local.app_name}-public-${var.environment}-${count.index}"
    Tier = "public"
  })
}

# Private subnets (one per AZ)
resource "aws_subnet" "private" {
  count             = length(data.aws_availability_zones.available.names)
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(local.cidr_block, 8, count.index + length(data.aws_availability_zones.available.names))
  availability_zone = data.aws_availability_zones.available.names[count.index]
  tags = merge(var.tags, {
    Name = "${local.app_name}-private-${var.environment}-${count.index}"
    Tier = "private"
  })
}

# Public route table
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
  tags = merge(var.tags, {
    Name = "${local.app_name}-public-rt-${var.environment}"
  })
}

# Associate public subnets with public route table
resource "aws_route_table_association" "public" {
  count          = length(aws_subnet.public)
  subnet_id      = aws_subnet.public[count.index].id
  route_table_id = aws_route_table.public.id
}

# Security group for ALB
resource "aws_security_group" "alb" {
  name        = "${local.app_name}-alb-sg-${var.environment}"
  description = "Security group for Application Load Balancer"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "HTTP from VPC"
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = [local.cidr_block]
  }

  ingress {
    description = "HTTPS from VPC"
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [local.cidr_block]
  }

  egress {
    description = "Allow outbound traffic to VPC"
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = [local.cidr_block]
  }

  tags = merge(var.tags, {
    Name = "${local.app_name}-alb-sg-${var.environment}"
  })
}

# Security group for ECS Fargate tasks
resource "aws_security_group" "ecs_tasks" {
  name        = "${local.app_name}-ecs-sg-${var.environment}"
  description = "Security group for ECS Fargate tasks"
  vpc_id      = aws_vpc.main.id

  ingress {
    description     = "Allow traffic from ALB"
    from_port       = local.app_port
    to_port         = local.app_port
    protocol        = "tcp"
    security_groups = [aws_security_group.alb.id]
  }

  egress {
    description = "Allow outbound traffic to VPC"
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = [local.cidr_block]
  }

  tags = merge(var.tags, {
    Name = "${local.app_name}-ecs-sg-${var.environment}"
  })
}

# ACM certificate (placeholder — requires DNS validation in production)
resource "aws_acm_certificate" "app" {
  domain_name       = "example.com"
  validation_method = "DNS"

  tags = merge(var.tags, {
    Name = "${local.app_name}-cert-${var.environment}"
  })

  lifecycle {
    create_before_destroy = true
  }
}

# Application Load Balancer
resource "aws_lb" "main" {
  name                       = "${local.app_name}-alb-${var.environment}"
  internal                   = true
  load_balancer_type         = "application"
  security_groups            = [aws_security_group.alb.id]
  subnets                    = aws_subnet.public[*].id
  drop_invalid_header_fields = true
  enable_deletion_protection = false

  tags = merge(var.tags, {
    Name = "${local.app_name}-alb-${var.environment}"
  })
}

# ALB target group
resource "aws_lb_target_group" "app" {
  name        = "${local.app_name}-tg-${var.environment}"
  port        = local.app_port
  protocol    = "HTTP"
  target_type = "ip"
  vpc_id      = aws_vpc.main.id

  health_check {
    enabled             = true
    healthy_threshold   = 2
    unhealthy_threshold = 2
    timeout             = 5
    interval            = 30
    path                = "/"
    port                = "traffic-port"
  }

  tags = merge(var.tags, {
    Name = "${local.app_name}-tg-${var.environment}"
  })
}

# ALB listener — HTTP redirect to HTTPS
resource "aws_lb_listener" "http_redirect" {
  load_balancer_arn = aws_lb.main.arn
  port              = 80
  protocol          = "HTTP"

  default_action {
    type = "redirect"
    redirect {
      protocol    = "HTTPS"
      port        = "443"
      host        = "#{host}"
      path        = "/#{path}"
      query       = "#{query}"
      status_code = "HTTP_301"
    }
  }
}

# ALB listener — HTTPS forward to target group
resource "aws_lb_listener" "https" {
  load_balancer_arn = aws_lb.main.arn
  port              = 443
  protocol          = "HTTPS"
  ssl_policy        = "ELBSecurityPolicy-TLS13-1-2-2021-06"
  certificate_arn   = aws_acm_certificate.app.arn

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.app.arn
  }
}

# IAM role for ECS task execution
resource "aws_iam_role" "ecs_task_exec" {
  name = "${local.app_name}-exec-role-${var.environment}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "ecs-tasks.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })

  tags = var.tags
}

# Attach AWS managed policy for ECS task execution (ECR, CloudWatch logs)
resource "aws_iam_role_policy_attachment" "ecs_task_exec" {
  role       = aws_iam_role.ecs_task_exec.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonECSTaskExecutionRolePolicy"
}

# IAM role for ECS task (application)
resource "aws_iam_role" "ecs_task" {
  name = "${local.app_name}-task-role-${var.environment}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "ecs-tasks.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })

  tags = var.tags
}

# Minimal inline policy for ECS task role (least privilege)
resource "aws_iam_policy" "ecs_task_minimal" {
  name = "${local.app_name}-task-policy-${var.environment}"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = "ecs:ListClusters"
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "ecs_task_minimal" {
  role       = aws_iam_role.ecs_task.name
  policy_arn = aws_iam_policy.ecs_task_minimal.arn
}

# ECR repository
resource "aws_ecr_repository" "app" {
  name                 = "${local.app_name}-${var.environment}"
  image_tag_mutability = "IMMUTABLE"

  image_scanning_configuration {
    scan_on_push = true
  }

  encryption_configuration {
    encryption_type = "AES256"
  }

  tags = merge(var.tags, {
    Name = "${local.app_name}-ecr-${var.environment}"
  })

  lifecycle {
    prevent_destroy = true
  }
}

# CloudWatch log group for container logs
resource "aws_cloudwatch_log_group" "app" {
  name              = "/ecs/${local.app_name}-${var.environment}"
  retention_in_days = 30

  tags = merge(var.tags, {
    Name = "${local.app_name}-logs-${var.environment}"
  })

  lifecycle {
    prevent_destroy = true
  }
}

# ECS cluster
resource "aws_ecs_cluster" "main" {
  name = "${local.app_name}-cluster-${var.environment}"

  setting {
    name  = "containerInsights"
    value = "enabled"
  }

  tags = merge(var.tags, {
    Name = "${local.app_name}-cluster-${var.environment}"
  })
}

# ECS task definition
resource "aws_ecs_task_definition" "app" {
  family                   = "${local.app_name}-task-${var.environment}"
  network_mode             = "awsvpc"
  requires_compatibilities = ["FARGATE"]
  cpu                      = "256"
  memory                   = "512"
  execution_role_arn       = aws_iam_role.ecs_task_exec.arn
  task_role_arn            = aws_iam_role.ecs_task.arn

  container_definitions = jsonencode([
    {
      name  = "go-app"
      image = "${local.account_id}.dkr.ecr.${local.region}.amazonaws.com/${aws_ecr_repository.app.name}:latest"
      essential = true
      portMappings = [
        {
          containerPort = local.app_port
          hostPort      = local.app_port
          protocol      = "tcp"
        }
      ]
      environment = [
        { name = "APP_ENV", value = var.environment }
      ]
      logConfiguration = {
        logDriver = "awslogs"
        options = {
          "awslogs-group"         = aws_cloudwatch_log_group.app.name
          "awslogs-region"        = local.region
          "awslogs-stream-prefix" = "ecs"
        }
      }
    }
  ])

  tags = merge(var.tags, {
    Name = "${local.app_name}-taskdef-${var.environment}"
  })
}

# ECS service (Fargate)
resource "aws_ecs_service" "app" {
  name            = "${local.app_name}-service-${var.environment}"
  cluster         = aws_ecs_cluster.main.id
  task_definition = aws_ecs_task_definition.app.arn
  desired_count   = 1
  launch_type     = "FARGATE"

  network_configuration {
    subnets         = aws_subnet.private[*].id
    security_groups = [aws_security_group.ecs_tasks.id]
    assign_public_ip = false
  }

  load_balancer {
    target_group_arn = aws_lb_target_group.app.arn
    container_name   = "go-app"
    container_port   = local.app_port
  }

  depends_on = [
    aws_lb_listener.https
  ]

  tags = merge(var.tags, {
    Name = "${local.app_name}-service-${var.environment}"
  })
}

# Terraform configuration block with version constraints
terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    tls = {
      source  = "hashicorp/tls"
      version = "~> 4.0"
    }
  }
}

# Data sources for well-known static metadata
data "aws_availability_zones" "available" {
  state = "available"
}

data "aws_region" "current" {}

data "aws_partition" "current" {}

locals {
  name_prefix    = "webapp"
  vpc_cidr       = "10.0.0.0/16"
  azs            = slice(data.aws_availability_zones.available.names, 0, 2)
  container_port = 80
  container_cpu  = 256
  container_mem  = 512
  desired_count  = 2
  min_capacity   = 1
  max_capacity   = 5
  # Placeholder image – replace with actual application image
  container_image = "nginx:latest"
}

# ------------------------------------------------------------------------------
# Networking
# ------------------------------------------------------------------------------
resource "aws_vpc" "main" {
  cidr_block           = local.vpc_cidr
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "${local.name_prefix}-vpc"
  }
}

resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "${local.name_prefix}-igw"
  }
}

# Public subnets – only used for NAT Gateway and Internet Gateway
resource "aws_subnet" "public" {
  count             = length(local.azs)
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(aws_vpc.main.cidr_block, 4, count.index)
  availability_zone = local.azs[count.index]
  map_public_ip_on_launch = false

  tags = {
    Name = "${local.name_prefix}-public-${local.azs[count.index]}"
  }
}

# Private subnets – used for ALB and ECS tasks
resource "aws_subnet" "private" {
  count             = length(local.azs)
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(aws_vpc.main.cidr_block, 4, count.index + length(local.azs))
  availability_zone = local.azs[count.index]

  tags = {
    Name = "${local.name_prefix}-private-${local.azs[count.index]}"
  }
}

# Elastic IP for NAT Gateway
resource "aws_eip" "nat" {
  domain = "vpc"

  tags = {
    Name = "${local.name_prefix}-nat-eip"
  }
}

# NAT Gateway – placed in the first public subnet
resource "aws_nat_gateway" "main" {
  allocation_id = aws_eip.nat.id
  subnet_id     = aws_subnet.public[0].id

  tags = {
    Name = "${local.name_prefix}-nat"
  }
}

# Public route table
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }

  tags = {
    Name = "${local.name_prefix}-public-rt"
  }
}

resource "aws_route_table_association" "public" {
  count          = length(local.azs)
  subnet_id      = aws_subnet.public[count.index].id
  route_table_id = aws_route_table.public.id
}

# Private route table – default route via NAT
resource "aws_route_table" "private" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.main.id
  }

  tags = {
    Name = "${local.name_prefix}-private-rt"
  }
}

resource "aws_route_table_association" "private" {
  count          = length(local.azs)
  subnet_id      = aws_subnet.private[count.index].id
  route_table_id = aws_route_table.private.id
}

# ------------------------------------------------------------------------------
# Security Groups – egress restricted to VPC CIDR
# ------------------------------------------------------------------------------
# ALB Security Group – allow HTTP and HTTPS only from within VPC (CloudFront origin)
resource "aws_security_group" "alb" {
  name        = "${local.name_prefix}-alb-sg"
  description = "Security group for internal ALB"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
    description = "HTTP from within VPC"
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
    description = "HTTPS from within VPC"
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  tags = {
    Name = "${local.name_prefix}-alb-sg"
  }
}

# ECS Task Security Group – allow only traffic from ALB on container port
resource "aws_security_group" "ecs_tasks" {
  name        = "${local.name_prefix}-ecs-tasks-sg"
  description = "Security group for ECS tasks"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port       = local.container_port
    to_port         = local.container_port
    protocol        = "tcp"
    security_groups = [aws_security_group.alb.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  tags = {
    Name = "${local.name_prefix}-ecs-tasks-sg"
  }
}

# ------------------------------------------------------------------------------
# TLS Certificate (self-signed, imported into ACM for internal ALB)
# ------------------------------------------------------------------------------
resource "tls_private_key" "this" {
  algorithm = "RSA"
}

resource "tls_self_signed_cert" "this" {
  private_key_pem = tls_private_key.this.private_key_pem

  subject {
    common_name         = "${local.name_prefix}.example.com"
    organization        = "Example Inc."
    organizational_unit = "WebApp"
  }

  validity_period_hours = 8760  # 1 year

  allowed_uses = [
    "key_encipherment",
    "digital_signature",
    "server_auth",
  ]

  dns_names = ["${local.name_prefix}.example.com"]
}

resource "aws_acm_certificate" "this" {
  private_key       = tls_private_key.this.private_key_pem
  certificate_body  = tls_self_signed_cert.this.cert_pem

  tags = {
    Name = "${local.name_prefix}-cert"
  }
}

# ------------------------------------------------------------------------------
# Internal Application Load Balancer (private subnets)
# ------------------------------------------------------------------------------
resource "aws_lb" "main" {
  name               = "${local.name_prefix}-alb"
  internal           = true
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb.id]
  subnets            = aws_subnet.private[*].id

  drop_invalid_header_fields = true
  enable_deletion_protection = false

  tags = {
    Name = "${local.name_prefix}-alb"
  }
}

resource "aws_lb_target_group" "main" {
  name     = "${local.name_prefix}-tg"
  port     = local.container_port
  protocol = "HTTP"
  vpc_id   = aws_vpc.main.id
  target_type = "ip"

  health_check {
    enabled             = true
    interval            = 30
    path                = "/"
    port                = "traffic-port"
    healthy_threshold   = 2
    unhealthy_threshold = 2
    timeout             = 5
    protocol            = "HTTP"
    matcher             = "200-399"
  }

  tags = {
    Name = "${local.name_prefix}-tg"
  }
}

# HTTP listener – redirects to HTTPS
resource "aws_lb_listener" "http" {
  load_balancer_arn = aws_lb.main.arn
  port              = 80
  protocol          = "HTTP"

  default_action {
    type = "redirect"

    redirect {
      protocol    = "HTTPS"
      port        = "443"
      status_code = "HTTP_301"
      host        = "#{host}"
      path        = "/#{path}"
      query       = "#{query}"
    }
  }
}

# HTTPS listener – forwards to target group
resource "aws_lb_listener" "https" {
  load_balancer_arn = aws_lb.main.arn
  port              = 443
  protocol          = "HTTPS"
  ssl_policy        = "ELBSecurityPolicy-TLS-1-2-2017-01"
  certificate_arn   = aws_acm_certificate.this.arn

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.main.arn
  }
}

# ------------------------------------------------------------------------------
# WAFv2 Web ACL for CloudFront (scope = CLOUDFRONT)
# ------------------------------------------------------------------------------
resource "aws_wafv2_web_acl" "cloudfront" {
  name        = "${local.name_prefix}-waf-cloudfront"
  description = "WAF for CloudFront distribution"
  scope       = "CLOUDFRONT"

  default_action {
    allow {}
  }

  rule {
    name     = "AWS-AWSManagedRulesCommonRuleSet"
    priority = 0

    override_action {
      none {}
    }

    statement {
      managed_rule_group_statement {
        name        = "AWSManagedRulesCommonRuleSet"
        vendor_name = "AWS"
      }
    }

    visibility_config {
      cloudwatch_metrics_enabled = false
      metric_name                = "AWSManagedRulesCommonRuleSet"
      sampled_requests_enabled   = false
    }
  }

  visibility_config {
    cloudwatch_metrics_enabled = false
    metric_name                = "${local.name_prefix}-waf-cloudfront"
    sampled_requests_enabled   = false
  }

  tags = {
    Name = "${local.name_prefix}-waf-cloudfront"
  }
}

# ------------------------------------------------------------------------------
# CloudFront Distribution – public HTTPS endpoint
# ------------------------------------------------------------------------------
resource "aws_cloudfront_distribution" "main" {
  enabled         = true
  is_ipv6_enabled = true
  comment         = "${local.name_prefix} CloudFront distribution"
  default_root_object = "/"
  web_acl_id      = aws_wafv2_web_acl.cloudfront.arn

  origin {
    domain_name = aws_lb.main.dns_name
    origin_id   = "${local.name_prefix}-origin"

    custom_origin_config {
      http_port              = 80
      https_port             = 443
      origin_protocol_policy = "http-only"     # CloudFront -> ALB via HTTP
      origin_ssl_protocols   = ["TLSv1.2"]
    }
  }

  default_cache_behavior {
    target_origin_id       = "${local.name_prefix}-origin"
    viewer_protocol_policy = "redirect-to-https"
    allowed_methods        = ["DELETE", "GET", "HEAD", "OPTIONS", "PATCH", "POST", "PUT"]
    cached_methods         = ["GET", "HEAD"]
    compress               = true

    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }

    min_ttl     = 0
    default_ttl = 3600
    max_ttl     = 86400
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }

  tags = {
    Name = "${local.name_prefix}-cloudfront"
  }
}

# ------------------------------------------------------------------------------
# CloudWatch Log Group for ECS
# ------------------------------------------------------------------------------
resource "aws_cloudwatch_log_group" "ecs" {
  name              = "/ecs/${local.name_prefix}"
  retention_in_days = 7

  tags = {
    Name = "${local.name_prefix}-logs"
  }
}

# ------------------------------------------------------------------------------
# IAM Roles and Policies for ECS
# ------------------------------------------------------------------------------
# ECS Task Execution Role – allows pulling images and writing logs
resource "aws_iam_role" "ecs_execution" {
  name = "${local.name_prefix}-ecs-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Effect = "Allow"
      Principal = {
        Service = "ecs-tasks.amazonaws.com"
      }
      Action = "sts:AssumeRole"
    }]
  })

  tags = {
    Name = "${local.name_prefix}-ecs-execution-role"
  }
}

resource "aws_iam_role_policy_attachment" "ecs_execution" {
  role       = aws_iam_role.ecs_execution.name
  policy_arn = "arn:${data.aws_partition.current.partition}:iam::aws:policy/service-role/AmazonECSTaskExecutionRolePolicy"
}

# ECS Task Role (optional, for container permissions)
resource "aws_iam_role" "ecs_task" {
  name = "${local.name_prefix}-ecs-task-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Effect = "Allow"
      Principal = {
        Service = "ecs-tasks.amazonaws.com"
      }
      Action = "sts:AssumeRole"
    }]
  })

  tags = {
    Name = "${local.name_prefix}-ecs-task-role"
  }
}

# ------------------------------------------------------------------------------
# ECS Cluster and Task Definition
# ------------------------------------------------------------------------------
resource "aws_ecs_cluster" "main" {
  name = "${local.name_prefix}-cluster"

  setting {
    name  = "containerInsights"
    value = "enabled"
  }

  tags = {
    Name = "${local.name_prefix}-cluster"
  }
}

resource "aws_ecs_task_definition" "main" {
  family                   = "${local.name_prefix}-td"
  network_mode             = "awsvpc"
  requires_compatibilities = ["FARGATE"]
  cpu                      = local.container_cpu
  memory                   = local.container_mem
  execution_role_arn       = aws_iam_role.ecs_execution.arn
  task_role_arn            = aws_iam_role.ecs_task.arn

  container_definitions = jsonencode([
    {
      name      = "${local.name_prefix}-container"
      image     = local.container_image
      essential = true
      portMappings = [
        {
          containerPort = local.container_port
          hostPort      = local.container_port
          protocol      = "tcp"
        }
      ]
      logConfiguration = {
        logDriver = "awslogs"
        options = {
          "awslogs-create-group"  = "false"
          "awslogs-group"         = aws_cloudwatch_log_group.ecs.name
          "awslogs-region"        = data.aws_region.current.name
          "awslogs-stream-prefix" = "ecs"
        }
      }
    }
  ])

  tags = {
    Name = "${local.name_prefix}-td"
  }
}

# ------------------------------------------------------------------------------
# ECS Service
# ------------------------------------------------------------------------------
resource "aws_ecs_service" "main" {
  name            = "${local.name_prefix}-service"
  cluster         = aws_ecs_cluster.main.id
  task_definition = aws_ecs_task_definition.main.arn
  desired_count   = local.desired_count
  launch_type     = "FARGATE"

  network_configuration {
    subnets         = aws_subnet.private[*].id
    security_groups = [aws_security_group.ecs_tasks.id]
  }

  load_balancer {
    target_group_arn = aws_lb_target_group.main.arn
    container_name   = "${local.name_prefix}-container"
    container_port   = local.container_port
  }

  depends_on = [
    aws_lb_listener.http
  ]

  tags = {
    Name = "${local.name_prefix}-service"
  }
}

# ------------------------------------------------------------------------------
# Auto Scaling (Application Auto Scaling for ECS Service)
# ------------------------------------------------------------------------------
resource "aws_appautoscaling_target" "ecs" {
  max_capacity       = local.max_capacity
  min_capacity       = local.min_capacity
  resource_id        = "service/${aws_ecs_cluster.main.name}/${aws_ecs_service.main.name}"
  scalable_dimension = "ecs:service:DesiredCount"
  service_namespace  = "ecs"
}

# Scale out policy – average CPU > 70%
resource "aws_appautoscaling_policy" "scale_out" {
  name               = "${local.name_prefix}-scale-out-cpu"
  policy_type        = "StepScaling"
  resource_id        = aws_appautoscaling_target.ecs.resource_id
  scalable_dimension = aws_appautoscaling_target.ecs.scalable_dimension
  service_namespace  = aws_appautoscaling_target.ecs.service_namespace

  step_scaling_policy_configuration {
    adjustment_type         = "ChangeInCapacity"
    cooldown                = 60
    metric_aggregation_type = "Average"

    step_adjustment {
      metric_interval_lower_bound = 0
      scaling_adjustment          = 1
    }
  }
}

# Scale in policy – average CPU < 30%
resource "aws_appautoscaling_policy" "scale_in" {
  name               = "${local.name_prefix}-scale-in-cpu"
  policy_type        = "StepScaling"
  resource_id        = aws_appautoscaling_target.ecs.resource_id
  scalable_dimension = aws_appautoscaling_target.ecs.scalable_dimension
  service_namespace  = aws_appautoscaling_target.ecs.service_namespace

  step_scaling_policy_configuration {
    adjustment_type         = "ChangeInCapacity"
    cooldown                = 60
    metric_aggregation_type = "Average"

    step_adjustment {
      metric_interval_upper_bound = 0
      scaling_adjustment          = -1
    }
  }
}

# CloudWatch metric alarms to trigger scaling policies
resource "aws_cloudwatch_metric_alarm" "cpu_high" {
  alarm_name          = "${local.name_prefix}-cpu-high"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = 2
  metric_name         = "CPUUtilization"
  namespace           = "AWS/ECS"
  period              = 60
  statistic           = "Average"
  threshold           = 70
  alarm_description   = "Scale out when CPU > 70%"
  dimensions = {
    ClusterName = aws_ecs_cluster.main.name
    ServiceName = aws_ecs_service.main.name
  }
  alarm_actions = [aws_appautoscaling_policy.scale_out.arn]
}

resource "aws_cloudwatch_metric_alarm" "cpu_low" {
  alarm_name          = "${local.name_prefix}-cpu-low"
  comparison_operator = "LessThanThreshold"
  evaluation_periods  = 2
  metric_name         = "CPUUtilization"
  namespace           = "AWS/ECS"
  period              = 60
  statistic           = "Average"
  threshold           = 30
  alarm_description   = "Scale in when CPU < 30%"
  dimensions = {
    ClusterName = aws_ecs_cluster.main.name
    ServiceName = aws_ecs_service.main.name
  }
  alarm_actions = [aws_appautoscaling_policy.scale_in.arn]
}

terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

variable "stream_name" {
  description = "Name of the Kinesis stream"
  type        = string
  default     = "my-kinesis-stream"
}

variable "tags" {
  description = "Common tags applied to all resources"
  type        = map(string)
  default = {
    Environment = "dev"
    ManagedBy   = "terraform"
  }
}

resource "aws_kinesis_stream" "this" {
  name             = var.stream_name
  shard_count      = 1
  retention_period = 24
  encryption_type  = "KMS"
  kms_key_id       = "alias/aws/kinesis"

  tags = merge(
    var.tags,
    { Name = var.stream_name }
  )

  lifecycle {
    prevent_destroy = true
  }
}

terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

resource "random_id" "bucket_suffix" {
  byte_length = 4
}

locals {
  bucket_name = "flink-app-code-${random_id.bucket_suffix.hex}"
}

# KMS Customer Managed Key for S3 encryption
resource "aws_kms_key" "s3_encryption_key" {
  description             = "CMK for S3 bucket encryption"
  deletion_window_in_days = 7
  enable_key_rotation     = true
}

# S3 bucket for Flink application code (external storage)
resource "aws_s3_bucket" "flink_app_code" {
  bucket = local.bucket_name

  lifecycle {
    prevent_destroy = true
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "flink_app_code" {
  bucket = aws_s3_bucket.flink_app_code.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm     = "aws:kms"
      kms_master_key_id = aws_kms_key.s3_encryption_key.arn
    }
  }
}

resource "aws_s3_bucket_public_access_block" "flink_app_code" {
  bucket = aws_s3_bucket.flink_app_code.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_s3_bucket_versioning" "flink_app_code" {
  bucket = aws_s3_bucket.flink_app_code.id

  versioning_configuration {
    status = "Enabled"
  }
}

# IAM role for Kinesis Analytics
data "aws_iam_policy_document" "kinesis_analytics_trust" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["kinesisanalytics.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

resource "aws_iam_role" "kinesis_analytics_role" {
  name               = "kinesis-analytics-flink-role"
  assume_role_policy = data.aws_iam_policy_document.kinesis_analytics_trust.json
}

# Custom policy for S3, KMS, and CloudWatch Logs permissions
data "aws_iam_policy_document" "kinesis_analytics_policy" {
  statement {
    effect = "Allow"
    actions = [
      "s3:GetObject",
      "s3:GetObjectVersion"
    ]
    resources = ["${aws_s3_bucket.flink_app_code.arn}/*"]
  }

  statement {
    effect = "Allow"
    actions = [
      "kms:Decrypt"
    ]
    resources = [
      aws_kms_key.s3_encryption_key.arn
    ]
  }

  statement {
    effect = "Allow"
    actions = [
      "logs:CreateLogStream",
      "logs:PutLogEvents"
    ]
    resources = [
      "${aws_cloudwatch_log_group.flink_app_logs.arn}:*"
    ]
  }
}

resource "aws_iam_policy" "kinesis_analytics_policy" {
  name   = "kinesis-analytics-flink-policy"
  policy = data.aws_iam_policy_document.kinesis_analytics_policy.json
}

resource "aws_iam_role_policy_attachment" "kinesis_analytics_policy" {
  role       = aws_iam_role.kinesis_analytics_role.name
  policy_arn = aws_iam_policy.kinesis_analytics_policy.arn
}

# CloudWatch Log Group and Stream
resource "aws_cloudwatch_log_group" "flink_app_logs" {
  name              = "/aws/kinesis-analytics/flink-app"
  retention_in_days = 30
}

resource "aws_cloudwatch_log_stream" "flink_app_log_stream" {
  name           = "flink-application-log-stream"
  log_group_name = aws_cloudwatch_log_group.flink_app_logs.name
}

# Variable for Flink JAR path (used inside s3_content_location)
variable "flink_jar_path" {
  description = "S3 key for the Flink application JAR"
  type        = string
  default     = "flink-app.jar"
}

# Kinesis Analytics V2 Application
resource "aws_kinesisanalyticsv2_application" "flink_app" {
  name                   = "flink-streaming-app"
  runtime_environment    = "FLINK-1_18"
  service_execution_role = aws_iam_role.kinesis_analytics_role.arn

  application_configuration {
    application_code_configuration {
      code_content_type = "ZIPFILE"
      code_content {
        s3_content_location {
          bucket_arn = aws_s3_bucket.flink_app_code.arn
          file_key   = var.flink_jar_path
        }
      }
    }

    run_configuration {
      application_restore_configuration {
        application_restore_type = "SKIP_RESTORE_FROM_SNAPSHOT"
      }
    }
  }

  lifecycle {
    create_before_destroy = true
  }
}

terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region                      = "us-east-1"
  skip_credentials_validation = true
  skip_requesting_account_id  = true
  skip_metadata_api_check     = true

  endpoints {
    route53 = "http://localhost:4566"
    sts     = "http://localhost:4566"
    ec2     = "http://localhost:4566"
  }
}

resource "aws_route53_zone" "example_com" {
  name = "example53.com"

  lifecycle {
    prevent_destroy = true
  }
}

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

resource "aws_route53_zone" "example53_com" {
  name = "example53.com"
}

resource "aws_route53_record" "example_a" {
  zone_id = aws_route53_zone.example53_com.zone_id
  name    = ""
  type    = "A"
  ttl     = 300
  records = ["192.0.2.1"]
}

resource "aws_vpc" "main" {
  cidr_block       = "10.0.0.0/16"
  instance_tenancy = "default"

  tags = {
    Name = "main"
  }
}

resource "aws_route53_zone" "private_zone" {
  name = "internal.example53.com"

  vpc {
    vpc_id     = aws_vpc.main.id
    vpc_region = "us-east-1"
  }
}

resource "aws_route53_record" "record" {
  zone_id = aws_route53_zone.private_zone.zone_id
  name    = "test.internal.example53.com"
  type    = "A"
  ttl     = 300
  records = ["10.0.0.1"]
}

# Required provider and version configuration
terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# CloudWatch metric alarm named "foobar"
resource "aws_cloudwatch_metric_alarm" "foobar" {
  alarm_name          = "foobar"
  comparison_operator = "GreaterThanOrEqualToThreshold"
  evaluation_periods  = 1
  metric_name         = "CPUUtilization"
  namespace           = "AWS/EC2"
  period              = 120
  statistic           = "Average"
  threshold           = 80
  alarm_description   = "Example alarm for CPU utilization"
}

# Route 53 health check based on the CloudWatch alarm
resource "aws_route53_health_check" "example" {
  type                            = "CLOUDWATCH_METRIC"
  request_interval                = 30
  insufficient_data_health_status = "Healthy"

  triggers = {
    name   = aws_cloudwatch_metric_alarm.foobar.alarm_name
    region = "us-east-1"
  }

  tags = {
    Name = "foobar-health-check"
  }
}

variable "domain_name" {
  description = "Domain name for the Route 53 hosted zone"
  type        = string
  default     = "example.com"
}

resource "aws_route53_zone" "primary" {
  name = var.domain_name

  lifecycle {
    prevent_destroy = true
  }
}

resource "aws_route53_record" "us_east_1" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = var.domain_name
  type    = "A"
  set_identifier = "us-east-1-endpoint"

  latency_routing_policy {
    region = "us-east-1"
  }

  ttl    = 60
  records = ["198.51.100.1"]
  health_check_id = null
}

resource "aws_route53_record" "eu_central_1" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = var.domain_name
  type    = "A"
  set_identifier = "eu-central-1-endpoint"

  latency_routing_policy {
    region = "eu-central-1"
  }

  ttl    = 60
  records = ["198.51.100.2"]
  health_check_id = null
}

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

variable "domain_name" {
  description = "The domain name for the Route 53 zone"
  type        = string
  default     = "example.com"
}

resource "aws_route53_zone" "primary_zone" {
  name = var.domain_name
}

resource "aws_route53_record" "us_record" {
  zone_id = aws_route53_zone.primary_zone.zone_id
  name    = aws_route53_zone.primary_zone.name
  type    = "A"
  ttl     = 300

  geolocation_routing_policy {
    continent = "US"
  }

  set_identifier = "us-endpoint"

  records = ["1.2.3.4"]
}

resource "aws_route53_record" "eu_record" {
  zone_id = aws_route53_zone.primary_zone.zone_id
  name    = aws_route53_zone.primary_zone.name
  type    = "A"
  ttl     = 300

  geolocation_routing_policy {
    continent = "EU"
  }

  set_identifier = "eu-endpoint"

  records = ["5.6.7.8"]
}

resource "aws_route53_record" "default_record" {
  zone_id = aws_route53_zone.primary_zone.zone_id
  name    = aws_route53_zone.primary_zone.name
  type    = "A"
  ttl     = 300

  geolocation_routing_policy {
    country = "*"
  }

  set_identifier = "default-endpoint"

  records = ["9.10.11.12"]
}

