terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-2.0.????????-x86_64-gp2"]
  }

  filter {
    name   = "state"
    values = ["available"]
  }
}

output "ami_id" {
  value = data.aws_ami.amazon_linux_2.id
}

data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-ebs"]
  }

  filter {
    name   = "owner-alias"
    values = ["amazon"]
  }

  filter {
    name   = "state"
    values = ["available"]
  }
}

output "ami_id" {
  description = "The ID of the latest Amazon Linux 2 AMI"
  value       = data.aws_ami.amazon_linux_2.id
}

terraform {
  required_version = "~> 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

locals {
  vpc_cidr = "10.0.0.0/16"
  name     = "redis-demo"
}

# Get available AZs
data "aws_availability_zones" "available" {
  state = "available"
}

# VPC
resource "aws_vpc" "main" {
  cidr_block           = local.vpc_cidr
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "${local.name}-vpc"
  }
}

# Private subnets in two AZs
resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(local.vpc_cidr, 8, count.index + 1)  # 10.0.1.0/24, 10.0.2.0/24
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "${local.name}-private-${count.index + 1}"
  }
}

# ElastiCache subnet group
resource "aws_elasticache_subnet_group" "main" {
  name       = "${local.name}-subnet-group"
  subnet_ids = aws_subnet.private[*].id
}

# Security group for Redis
resource "aws_security_group" "redis" {
  name        = "${local.name}-redis-sg"
  description = "Security group for Redis instance"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "Redis from VPC"
    from_port   = 6379
    to_port     = 6379
    protocol    = "tcp"
    cidr_blocks = [local.vpc_cidr]
  }

  egress {
    description = "Allow all traffic inside VPC"
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = [local.vpc_cidr]
  }

  tags = {
    Name = "${local.name}-redis-sg"
  }
}

# ElastiCache parameter group for Redis 7.1
resource "aws_elasticache_parameter_group" "main" {
  name        = "${local.name}-redis-params"
  family      = "redis7"
  description = "Parameter group for Redis 7.1"

  tags = {
    Name = "${local.name}-redis-params"
  }
}

# Random password for Redis AUTH token
resource "random_password" "redis_auth" {
  length  = 16
  special = true
  # avoid characters that might cause issues in Redis
  override_special = "!@#$%^&*()-_=+[]{}<>?"
}

# Secrets Manager secret to store the AUTH token
resource "aws_secretsmanager_secret" "redis_auth" {
  name        = "${local.name}-redis-auth-token"
  description = "Redis AUTH token for ${local.name}"
}

resource "aws_secretsmanager_secret_version" "redis_auth" {
  secret_id     = aws_secretsmanager_secret.redis_auth.id
  secret_string = jsonencode({
    auth_token = random_password.redis_auth.result
  })
}

# ElastiCache replication group (single-node Redis)
resource "aws_elasticache_replication_group" "main" {
  lifecycle {
    prevent_destroy = true
  }

  replication_group_id          = "${local.name}-redis"
  description                   = "Single-node Redis 7.1 instance"
  engine                        = "redis"
  engine_version                = "7.1"
  node_type                     = "cache.t3.micro"
  num_cache_clusters            = 1
  parameter_group_name          = aws_elasticache_parameter_group.main.name
  subnet_group_name             = aws_elasticache_subnet_group.main.name
  security_group_ids            = [aws_security_group.redis.id]
  port                          = 6379
  automatic_failover_enabled    = false
  auto_minor_version_upgrade    = true
  at_rest_encryption_enabled    = true
  transit_encryption_enabled    = true
  auth_token                    = random_password.redis_auth.result
  snapshot_retention_limit      = 1
  apply_immediately             = false

  tags = {
    Name = "${local.name}-redis"
  }
}

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
