provider "aws" {
  region = "us-east-1"
}

variable "elasticache_user_name" {
  description = "Name of the ElastiCache Redis user"
  type        = string
  default     = "redis_app_user"
}

resource "random_password" "elasticache_user_password" {
  length           = 32
  special          = true
  override_special = "!@#$%^&*()_+-=[]{}|;:,.<>?"
  min_lower        = 1
  min_upper        = 1
  min_numeric      = 1
  min_special      = 1
}

resource "aws_secretsmanager_secret" "elasticache_user_password" {
  name = "elasticache-${var.elasticache_user_name}-password"

  lifecycle {
    prevent_destroy = true
  }
}

resource "aws_secretsmanager_secret_version" "elasticache_user_password" {
  secret_id     = aws_secretsmanager_secret.elasticache_user_password.id
  secret_string = random_password.elasticache_user_password.result
}

resource "aws_elasticache_user" "redis" {
  user_id       = var.elasticache_user_name
  user_name     = var.elasticache_user_name
  engine        = "REDIS"
  access_string = "on ~* +@all"
  authentication_mode {
    type      = "password"
    passwords = [aws_secretsmanager_secret_version.elasticache_user_password.secret_string]
  }
}

