# ------------------------------------------------------------------------------
# Data sources for static metadata
# ------------------------------------------------------------------------------
data "aws_availability_zones" "available" {
  state = "available"
}

data "aws_caller_identity" "current" {}

data "aws_region" "current" {}

# ------------------------------------------------------------------------------
# Locals for naming and consistency
# ------------------------------------------------------------------------------
locals {
  name_prefix = "redshift-demo"
  vpc_cidr    = "10.0.0.0/16"
  subnet_cidr = "10.0.1.0/24"
  az          = data.aws_availability_zones.available.names[0]
  bucket_name = "${local.name_prefix}-${data.aws_caller_identity.current.account_id}-${data.aws_region.current.name}"
}

# ------------------------------------------------------------------------------
# KMS Key for encryption (used by Redshift and S3)
# ------------------------------------------------------------------------------
resource "aws_kms_key" "main" {
  description             = "CMK for Redshift cluster and S3 bucket encryption"
  deletion_window_in_days = 10
  enable_key_rotation     = true
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "Enable Root Account Access"
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action   = "kms:*"
        Resource = "*"
      },
      {
        Sid    = "Allow Redshift IAM Role to Use Key"
        Effect = "Allow"
        Principal = {
          AWS = aws_iam_role.redshift.arn
        }
        Action = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey"
        ]
        Resource = "*"
      },
      {
        Sid    = "Allow S3 Service to Use Key"
        Effect = "Allow"
        Principal = {
          Service = "s3.amazonaws.com"
        }
        Action = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey"
        ]
        Resource = "*"
        Condition = {
          StringEquals = {
            "kms:ViaService" = "s3.${data.aws_region.current.name}.amazonaws.com"
          }
        }
      }
    ]
  })
}

resource "aws_kms_alias" "main" {
  name          = "alias/${local.name_prefix}-key"
  target_key_id = aws_kms_key.main.id
}

# ------------------------------------------------------------------------------
# VPC
# ------------------------------------------------------------------------------
resource "aws_vpc" "main" {
  cidr_block           = local.vpc_cidr
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "${local.name_prefix}-vpc"
  }
}

# ------------------------------------------------------------------------------
# Subnet
# ------------------------------------------------------------------------------
resource "aws_subnet" "public" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = local.subnet_cidr
  availability_zone = local.az
  map_public_ip_on_launch = false

  tags = {
    Name = "${local.name_prefix}-subnet"
  }
}

# ------------------------------------------------------------------------------
# Internet Gateway (for outbound - though Redshift may not need it)
# ------------------------------------------------------------------------------
resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "${local.name_prefix}-igw"
  }
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }

  tags = {
    Name = "${local.name_prefix}-rtb"
  }
}

resource "aws_route_table_association" "public" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

# VPC Gateway Endpoint for S3 (private access)
resource "aws_vpc_endpoint" "s3" {
  vpc_id       = aws_vpc.main.id
  service_name = "com.amazonaws.${data.aws_region.current.name}.s3"
  vpc_endpoint_type = "Gateway"
  route_table_ids = [aws_route_table.public.id]
}

# ------------------------------------------------------------------------------
# S3 Bucket for COPY operations
# ------------------------------------------------------------------------------
resource "aws_s3_bucket" "data" {
  bucket        = local.bucket_name
  force_destroy = false

  lifecycle {
    prevent_destroy = true
  }

  tags = {
    Name = "${local.name_prefix}-bucket"
  }
}

resource "aws_s3_bucket_versioning" "data" {
  bucket = aws_s3_bucket.data.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "data" {
  bucket = aws_s3_bucket.data.id
  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm     = "aws:kms"
      kms_master_key_id = aws_kms_key.main.arn
    }
  }
}

resource "aws_s3_bucket_public_access_block" "data" {
  bucket                  = aws_s3_bucket.data.id
  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# ------------------------------------------------------------------------------
# Security Group (tightened egress)
# ------------------------------------------------------------------------------
resource "aws_security_group" "redshift" {
  name        = "${local.name_prefix}-sg"
  description = "Allow inbound Redshift traffic from VPC CIDR"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = [local.vpc_cidr]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = [local.vpc_cidr]  # restricted to VPC only
  }

  tags = {
    Name = "${local.name_prefix}-sg"
  }
}

# ------------------------------------------------------------------------------
# Redshift Subnet Group
# ------------------------------------------------------------------------------
resource "aws_redshift_subnet_group" "main" {
  name       = "${local.name_prefix}-subnet-group"
  subnet_ids = [aws_subnet.public.id]

  tags = {
    Name = "${local.name_prefix}-subnet-group"
  }
}

# ------------------------------------------------------------------------------
# IAM Role for Redshift
# ------------------------------------------------------------------------------
resource "aws_iam_role" "redshift" {
  name = "${local.name_prefix}-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })
}

resource "aws_iam_role_policy" "redshift_s3" {
  name = "${local.name_prefix}-policy"
  role = aws_iam_role.redshift.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.data.arn,
          "${aws_s3_bucket.data.arn}/*"
        ]
      }
    ]
  })
}

# ------------------------------------------------------------------------------
# Random Password
# ------------------------------------------------------------------------------
resource "random_password" "master" {
  length           = 16
  special          = true
  override_special = "!@#$%^&*()_+-=[]{}|;:,.<>?"
}

# ------------------------------------------------------------------------------
# Secrets Manager
# ------------------------------------------------------------------------------
resource "aws_secretsmanager_secret" "redshift_master" {
  name = "${local.name_prefix}-master-password"

  lifecycle {
    prevent_destroy = true
  }
}

resource "aws_secretsmanager_secret_version" "redshift_master" {
  secret_id     = aws_secretsmanager_secret.redshift_master.id
  secret_string = random_password.master.result
}

# ------------------------------------------------------------------------------
# Redshift Cluster (encrypted with CMK, using default parameter group)
# ------------------------------------------------------------------------------
resource "aws_redshift_cluster" "main" {
  cluster_identifier        = "${local.name_prefix}-cluster"
  database_name             = "dev"
  master_username           = "admin"
  master_password           = random_password.master.result
  node_type                 = "dc2.large"
  cluster_type              = "single-node"
  number_of_nodes           = 1
  publicly_accessible       = false
  encrypted                 = true
  kms_key_id                = aws_kms_key.main.arn
  cluster_subnet_group_name = aws_redshift_subnet_group.main.name
  vpc_security_group_ids    = [aws_security_group.redshift.id]
  iam_roles                 = [aws_iam_role.redshift.arn]
  cluster_parameter_group_name = "default.redshift-1.0"
  skip_final_snapshot       = true

  depends_on = [
    aws_vpc_endpoint.s3
  ]

  tags = {
    Name = "${local.name_prefix}-cluster"
  }
}

# ------------------------------------------------------------------------------
# Outputs
# ------------------------------------------------------------------------------
output "cluster_endpoint" {
  value = aws_redshift_cluster.main.endpoint
}

output "master_password_secret_arn" {
  description = "ARN of the Secrets Manager secret containing the master password"
  value       = aws_secretsmanager_secret.redshift_master.arn
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name        = "main-vpc"
    Environment = "development"
  }
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  availability_zone = data.aws_availability_zones.available.names[0]
  cidr_block        = "10.0.1.0/24"

  tags = {
    Name        = "subnet-us-east-1a"
    Environment = "development"
  }
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  availability_zone = data.aws_availability_zones.available.names[1]
  cidr_block        = "10.0.2.0/24"

  tags = {
    Name        = "subnet-us-east-1b"
    Environment = "development"
  }
}

resource "aws_redshift_subnet_group" "main" {
  name       = "main-redshift-subnet-group"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  tags = {
    Name        = "main-redshift-subnet-group"
    Environment = "development"
  }
}

terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = ">= 4.0"
    }
  }
}

locals {
  name_prefix = "composite-alarm"
  environment = "production"
  common_tags = {
    Name        = local.name_prefix
    Environment = local.environment
    ManagedBy   = "terraform"
  }
}

resource "aws_kms_key" "sns" {
  description             = "KMS key for SNS composite-alarm notifications"
  deletion_window_in_days = 7
  enable_key_rotation     = true

  tags = local.common_tags
}

resource "aws_kms_alias" "sns" {
  name          = "alias/composite-alarm-sns"
  target_key_id = aws_kms_key.sns.key_id
}

resource "aws_sns_topic" "notifications" {
  name              = "${local.name_prefix}-notifications"
  kms_master_key_id = aws_kms_alias.sns.name

  tags = local.common_tags

  depends_on = [aws_kms_alias.sns]
}

resource "aws_cloudwatch_metric_alarm" "high_cpu" {
  alarm_name          = "${local.name_prefix}-high-cpu"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = 1
  metric_name         = "CPUUtilization"
  namespace           = "Custom/App"
  period              = 60
  statistic           = "Average"
  threshold           = 80
  alarm_description   = "This alarm triggers when CPU utilization exceeds 80%"

  tags = merge(local.common_tags, { Name = "${local.name_prefix}-high-cpu" })
}

resource "aws_cloudwatch_metric_alarm" "high_memory" {
  alarm_name          = "${local.name_prefix}-high-memory"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = 1
  metric_name         = "MemoryUtilization"
  namespace           = "Custom/App"
  period              = 60
  statistic           = "Average"
  threshold           = 80
  alarm_description   = "This alarm triggers when memory utilization exceeds 80%"

  tags = merge(local.common_tags, { Name = "${local.name_prefix}-high-memory" })
}

resource "aws_cloudwatch_composite_alarm" "main" {
  alarm_name        = "${local.name_prefix}-high-cpu-or-memory"
  alarm_description = "Composite alarm that triggers if either CPU or memory utilization exceeds threshold"
  alarm_rule        = "ALARM(\"${aws_cloudwatch_metric_alarm.high_cpu.alarm_name}\") OR ALARM(\"${aws_cloudwatch_metric_alarm.high_memory.alarm_name}\")"
  alarm_actions     = [aws_sns_topic.notifications.arn]
  ok_actions        = [aws_sns_topic.notifications.arn]

  tags = merge(local.common_tags, { Name = "${local.name_prefix}-high-cpu-or-memory" })
}

terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = ">= 5.0"
    }
  }
}

# Static provider metadata (permitted)
data "aws_region" "current" {}
data "aws_caller_identity" "current" {}

# Customer managed KMS key for SNS topic encryption
resource "aws_kms_key" "sns" {
  description             = "CMK for SNS topic alarm-topic"
  key_usage               = "ENCRYPT_DECRYPT"
  customer_master_key_spec = "SYMMETRIC_DEFAULT"
  deletion_window_in_days = 7
  enable_key_rotation     = true

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "Allow SNS service to use the key"
        Effect = "Allow"
        Principal = {
          Service = "sns.amazonaws.com"
        }
        Action = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:GenerateDataKey*",
          "kms:ReEncrypt*",
          "kms:CreateGrant",
          "kms:DescribeKey"
        ]
        Resource = "*"
        Condition = {
          ArnLike = {
            "aws:SourceArn" = "arn:aws:sns:${data.aws_region.current.region}:${data.aws_caller_identity.current.account_id}:alarm-topic"
          }
        }
      }
    ]
  })
}

# SQS queue as metric source for the alarm
resource "aws_sqs_queue" "alarm_queue" {
  name                    = "alarm-queue"
  sqs_managed_sse_enabled = true

  lifecycle {
    prevent_destroy = true
  }
}

# SNS topic to receive alarm notifications
resource "aws_sns_topic" "alarm_topic" {
  name              = "alarm-topic"
  kms_master_key_id = aws_kms_key.sns.arn

  lifecycle {
    prevent_destroy = true
  }
}

# CloudWatch Metric Alarm on ApproximateNumberOfMessagesVisible for the SQS queue
resource "aws_cloudwatch_metric_alarm" "example" {
  alarm_name          = "sqs-messages-visible-alarm"
  comparison_operator = "GreaterThanOrEqualToThreshold"
  evaluation_periods  = 2
  metric_name         = "ApproximateNumberOfMessagesVisible"
  namespace           = "AWS/SQS"
  period              = 300
  statistic           = "Average"
  threshold           = 100
  alarm_description   = "Alarm when ApproximateNumberOfMessagesVisible Average >= 100 for 2 consecutive 5-minute periods"
  alarm_actions       = [aws_sns_topic.alarm_topic.arn]

  dimensions = {
    QueueName = aws_sqs_queue.alarm_queue.name
  }
}

