  comparison_operator = "GreaterThanOrEqualToThreshold"
  evaluation_periods  = 2
  metric_name         = "CPUUtilization"
  namespace           = "AWS/EC2"
  period              = 120
  statistic           = "Average"
  threshold           = 80
  treat_missing_data  = "notBreaching"

  dimensions = {
    InstanceId = aws_instance.example.id
  }

  alarm_description = "Monitors CPU utilization for EC2 instance. Alarm triggers when average >= 80% for two consecutive 2-minute periods."
}

terraform {
  required_providers {
