variable "table_name" {
  description = "Name of the DynamoDB table"
  type        = string
  default     = "my-dynamodb-table"
}

variable "environment" {
  description = "Environment tag"
  type        = string
  default     = "dev"
}

resource "aws_dynamodb_table" "main" {
  name           = var.table_name
  billing_mode   = "PROVISIONED"
  read_capacity  = 20
  write_capacity = 20
  hash_key       = "Id"

  attribute {
    name = "Id"
    type = "S"
  }

  server_side_encryption {
    enabled = true
  }

  point_in_time_recovery {
    enabled = true
  }

  tags = {
    Name        = var.table_name
    Environment = var.environment
  }

  lifecycle {
    prevent_destroy = true
  }
}

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

variable "table_name" {
  description = "Name of the DynamoDB table"
  type        = string
  default     = "items"
}

variable "item_attributes" {
  description = "JSON-encoded DynamoDB AttributeValue map for the table item. Must contain a key matching the table's hash key, with typed values."
  type        = string
  default     = <<-JSON
{
  "id": {"S": "example-item-id"},
  "data": {"S": "example-value"}
}
JSON
}

resource "aws_dynamodb_table" "main" {
  name         = var.table_name
  billing_mode = "PAY_PER_REQUEST"
  hash_key     = "id"

  attribute {
    name = "id"
    type = "S"
  }

  server_side_encryption {
    enabled = true
  }

  lifecycle {
    prevent_destroy = true
  }
}

resource "aws_dynamodb_table_item" "example" {
  table_name = aws_dynamodb_table.main.name
  hash_key   = aws_dynamodb_table.main.hash_key
  item       = var.item_attributes
}

variable "table_name" {
  description = "Name of the DynamoDB table"
  type        = string
  default     = "app-table"
}

resource "aws_dynamodb_table" "this" {
  name         = var.table_name
  billing_mode = "PAY_PER_REQUEST"
  hash_key     = "id"

  attribute {
    name = "id"
    type = "S"
  }

  server_side_encryption {
    enabled = true
  }

  lifecycle {
    prevent_destroy = true
  }
}

terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

data "aws_region" "current" {}

data "aws_caller_identity" "current" {}

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "sagemaker-vpc"
  }
}

resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone = data.aws_availability_zones.available.names[count.index]

  map_public_ip_on_launch = false

  tags = {
    Name = "sagemaker-private-${count.index + 1}"
  }
}

resource "aws_security_group" "sagemaker_domain" {
  name_prefix = "sagemaker-domain-"
  description = "Security group for SageMaker Domain"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "HTTPS from VPC"
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    description = "HTTPS to VPC (includes VPC endpoints)"
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  tags = {
    Name = "sagemaker-domain-sg"
  }
}

resource "aws_security_group" "vpc_endpoints" {
  name_prefix = "vpc-endpoints-"
  description = "Security group for VPC interface endpoints"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "HTTPS from VPC"
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    description = "All outbound within VPC"
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  tags = {
    Name = "vpc-endpoints-sg"
  }
}

resource "aws_vpc_endpoint" "s3" {
  vpc_id          = aws_vpc.main.id
  service_name    = "com.amazonaws.${data.aws_region.current.name}.s3"
  vpc_endpoint_type = "Gateway"
  route_table_ids = [aws_route_table.private.id]

  tags = {
    Name = "s3-gateway"
  }
}

resource "aws_vpc_endpoint" "logs" {
  vpc_id              = aws_vpc.main.id
  service_name        = "com.amazonaws.${data.aws_region.current.name}.logs"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = aws_subnet.private[*].id
  security_group_ids  = [aws_security_group.vpc_endpoints.id]
  private_dns_enabled = true

  tags = {
    Name = "logs-interface"
  }
}

resource "aws_vpc_endpoint" "sagemaker_api" {
  vpc_id              = aws_vpc.main.id
  service_name        = "com.amazonaws.${data.aws_region.current.name}.sagemaker.api"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = aws_subnet.private[*].id
  security_group_ids  = [aws_security_group.vpc_endpoints.id]
  private_dns_enabled = true

  tags = {
    Name = "sagemaker-api"
  }
}

resource "aws_vpc_endpoint" "sagemaker_runtime" {
  vpc_id              = aws_vpc.main.id
  service_name        = "com.amazonaws.${data.aws_region.current.name}.sagemaker.runtime"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = aws_subnet.private[*].id
  security_group_ids  = [aws_security_group.vpc_endpoints.id]
  private_dns_enabled = true

  tags = {
    Name = "sagemaker-runtime"
  }
}

resource "aws_vpc_endpoint" "sagemaker_notebook" {
  vpc_id              = aws_vpc.main.id
  service_name        = "com.amazonaws.${data.aws_region.current.name}.sagemaker.notebook"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = aws_subnet.private[*].id
  security_group_ids  = [aws_security_group.vpc_endpoints.id]
  private_dns_enabled = true

  tags = {
    Name = "sagemaker-notebook"
  }
}

resource "aws_route_table" "private" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "sagemaker-private-rt"
  }
}

resource "aws_route_table_association" "private" {
  count          = 2
  subnet_id      = aws_subnet.private[count.index].id
  route_table_id = aws_route_table.private.id
}

resource "aws_iam_role" "sagemaker_execution" {
  name_prefix = "sagemaker-execution-"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })

  tags = {
    Name = "sagemaker-execution-role"
  }
}

resource "aws_iam_policy" "sagemaker_domain_policy" {
  name_prefix = "sagemaker-domain-policy-"
  description = "Least privilege policy for SageMaker Domain execution role"
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "sagemaker:CreatePresignedDomainUrl",
          "sagemaker:DescribeDomain",
          "sagemaker:ListApps",
          "sagemaker:DescribeUserProfile"
        ]
        Resource = "arn:aws:sagemaker:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:domain/*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:DeleteObject",
          "s3:ListBucket"
        ]
        Resource = [
          "arn:aws:s3:::sagemaker-${data.aws_region.current.name}-${data.aws_caller_identity.current.account_id}",
          "arn:aws:s3:::sagemaker-${data.aws_region.current.name}-${data.aws_caller_identity.current.account_id}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:PutLogEvents",
          "logs:CreateLogGroup",
          "logs:CreateLogStream"
        ]
        Resource = "arn:aws:logs:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:log-group:/aws/sagemaker/*"
      },
      {
        Effect = "Allow"
        Action = [
          "kms:Decrypt",
          "kms:Encrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey"
        ]
        Resource = aws_kms_key.sagemaker.arn
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "sagemaker_domain_policy_attachment" {
  role       = aws_iam_role.sagemaker_execution.name
  policy_arn = aws_iam_policy.sagemaker_domain_policy.arn
}

resource "aws_kms_key" "sagemaker" {
  description             = "KMS key for SageMaker Domain encryption"
  enable_key_rotation     = true
  deletion_window_in_days = 30

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
        Action = [
          "kms:Decrypt",
          "kms:Encrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Principal = {
          AWS = aws_iam_role.sagemaker_execution.arn
        }
        Action = [
          "kms:Decrypt",
          "kms:Encrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey"
        ]
        Resource = "*"
      }
    ]
  })

  tags = {
    Name = "sagemaker-kms-key"
  }
}

resource "aws_sagemaker_domain" "studio" {
  domain_name = "studio-domain"
  auth_mode   = "IAM"
  vpc_id      = aws_vpc.main.id
  subnet_ids  = aws_subnet.private[*].id

  default_user_settings {
    execution_role = aws_iam_role.sagemaker_execution.arn
    security_groups = [aws_security_group.sagemaker_domain.id]
  }

  kms_key_id = aws_kms_key.sagemaker.arn

  lifecycle {
    prevent_destroy = true
  }

  tags = {
    Name = "sagemaker-domain"
  }
}

terraform {
  required_version = ">= 1.0"

  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.5"
    }
  }
}

# Random suffix for S3 bucket name
resource "random_id" "model_bucket_suffix" {
  byte_length = 8
}

# KMS CMK for S3 bucket encryption
resource "aws_kms_key" "sagemaker_model_bucket" {
  description             = "KMS CMK for SageMaker model artifacts bucket"
  deletion_window_in_days = 10
  enable_key_rotation     = true
}

# S3 bucket for model artifacts
resource "aws_s3_bucket" "model_artifacts" {
  bucket = "sagemaker-model-artifacts-${random_id.model_bucket_suffix.hex}"

  tags = {
    Name = "SageMaker Model Artifacts"
  }
}

resource "aws_s3_bucket_public_access_block" "model_artifacts" {
  bucket = aws_s3_bucket.model_artifacts.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_s3_bucket_versioning" "model_artifacts" {
  bucket = aws_s3_bucket.model_artifacts.id

  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "model_artifacts" {
  bucket = aws_s3_bucket.model_artifacts.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm     = "aws:kms"
      kms_master_key_id = aws_kms_key.sagemaker_model_bucket.arn
    }
  }
}

# Data source for current region (reliable in all environments)
data "aws_region" "current" {}

# Data source for prebuilt K-Means ECR image
data "aws_sagemaker_prebuilt_ecr_image" "kmeans" {
  repository_name = "kmeans"
}

# IAM role for SageMaker execution
data "aws_iam_policy_document" "sagemaker_trust" {
  statement {
    actions = ["sts:AssumeRole"]

    principals {
      type        = "Service"
      identifiers = ["sagemaker.amazonaws.com"]
    }
  }
}

resource "aws_iam_role" "sagemaker_execution" {
  name               = "sagemaker-execution-role"
  assume_role_policy = data.aws_iam_policy_document.sagemaker_trust.json

  tags = {
    Name = "SageMaker Execution Role"
  }
}

# Least-privilege policy for SageMaker execution role
data "aws_iam_policy_document" "sagemaker_policy" {
  statement {
    actions = [
      "s3:GetObject",
      "s3:ListBucket"
    ]
    resources = [
      aws_s3_bucket.model_artifacts.arn,
      "${aws_s3_bucket.model_artifacts.arn}/*"
    ]
  }

  statement {
    actions = [
      "kms:Decrypt"
    ]
    resources = [
      aws_kms_key.sagemaker_model_bucket.arn
    ]
  }

  statement {
    actions = [
      "ecr:GetDownloadUrlForLayer",
      "ecr:BatchGetImage",
      "ecr:BatchCheckLayerAvailability"
    ]
    resources = [
      "arn:aws:ecr:${data.aws_region.current.name}:${data.aws_sagemaker_prebuilt_ecr_image.kmeans.registry_id}:repository/${data.aws_sagemaker_prebuilt_ecr_image.kmeans.repository_name}"
    ]
  }

  statement {
    actions = [
      "logs:CreateLogGroup",
      "logs:CreateLogStream",
      "logs:PutLogEvents"
    ]
    resources = ["*"]
  }
}

resource "aws_iam_policy" "sagemaker_execution" {
  name        = "sagemaker-execution-policy"
  description = "Least-privilege policy for SageMaker execution role"
  policy      = data.aws_iam_policy_document.sagemaker_policy.json
}

resource "aws_iam_role_policy_attachment" "sagemaker_execution" {
  role       = aws_iam_role.sagemaker_execution.name
  policy_arn = aws_iam_policy.sagemaker_execution.arn
}

# SageMaker model using the K-Means image
resource "aws_sagemaker_model" "kmeans" {
  name               = "kmeans-model"
  execution_role_arn = aws_iam_role.sagemaker_execution.arn

  primary_container {
    image = data.aws_sagemaker_prebuilt_ecr_image.kmeans.registry_path
  }

  tags = {
    Name = "KMeans Model"
  }
}

terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_vpc" "sagemaker" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "sagemaker-vpc"
  }
}

resource "aws_subnet" "public" {
  vpc_id            = aws_vpc.sagemaker.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = data.aws_availability_zones.available.names[0]
  tags = {
    Name = "sagemaker-public-subnet"
  }
}

resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.sagemaker.id
  tags = {
    Name = "sagemaker-igw"
  }
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.sagemaker.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }
  tags = {
    Name = "sagemaker-public-rt"
  }
}

resource "aws_route_table_association" "public" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

resource "aws_security_group" "notebook" {
  name        = "sagemaker-notebook-sg"
  description = "Security group for SageMaker notebook instance"
  vpc_id      = aws_vpc.sagemaker.id

  ingress {
    description = "SSH from VPC"
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    description = "Outbound traffic to VPC only"
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["10.0.0.0/16"]
  }

  tags = {
    Name = "sagemaker-notebook-sg"
  }
}

resource "aws_iam_role" "sagemaker" {
  name = "sagemaker-notebook-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "sagemaker_full_access" {
  role       = aws_iam_role.sagemaker.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

resource "aws_sagemaker_notebook_instance" "my_notebook" {
  name          = "my-notebook-instance"
  role_arn      = aws_iam_role.sagemaker.arn
  instance_type = "ml.t2.medium"
  subnet_id     = aws_subnet.public.id
  security_groups = [aws_security_group.notebook.id]
  direct_internet_access = "Enabled"

  tags = {
    Name = "my-notebook-instance"
  }
}

terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

locals {
  pipeline_bucket_name = "sagemaker-pipeline-artifacts-${data.aws_caller_identity.this.account_id}-${data.aws_region.this.name}"
  training_image       = data.aws_sagemaker_prebuilt_ecr_image.scikit_learn.registry_path

  pipeline_definition = jsonencode({
    Version = "2020-12-01"
    Metadata = {}
    Parameters = []
    PipelineExperimentConfig = {
      ExperimentName = "MyExperiment"
      TrialName      = "MyTrial"
    }
    Steps = [
      {
        Name = "MyTrainingStep"
        Type = "Training"
        Arguments = {
          AlgorithmSpecification = {
            TrainingImage = local.training_image
            TrainingInputMode = "File"
          }
          OutputDataConfig = {
            S3OutputPath = "s3://${local.pipeline_bucket_name}/output"
          }
          StoppingCondition = {
            MaxRuntimeInSeconds = 86400
          }
          ResourceConfig = {
            InstanceCount = 1
            InstanceType  = "ml.m5.large"
            VolumeSizeInGB = 30
          }
          RoleArn = aws_iam_role.pipeline_exec.arn
          InputDataConfig = []
          HyperParameters = {}
        }
      }
    ]
  })
}

data "aws_region" "this" {}
data "aws_caller_identity" "this" {}

data "aws_sagemaker_prebuilt_ecr_image" "scikit_learn" {
  repository_name = "sagemaker-scikit-learn"
  image_tag       = "0.23-1-cpu-py3"
}

# KMS key for S3 bucket encryption
resource "aws_kms_key" "sagemaker_pipeline" {
  description             = "KMS key for SageMaker pipeline artifacts"
  deletion_window_in_days = 30
  enable_key_rotation     = true

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "EnableIAMUserPermissions"
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.this.account_id}:root"
        }
        Action   = "kms:*"
        Resource = "*"
      },
      {
        Sid    = "AllowS3Service"
        Effect = "Allow"
        Principal = {
          Service = "s3.amazonaws.com"
        }
        Action = [
          "kms:GenerateDataKey",
          "kms:Decrypt"
        ]
        Resource = "*"
      }
    ]
  })
}

# S3 bucket for pipeline artifacts
resource "aws_s3_bucket" "pipeline_artifacts" {
  bucket = local.pipeline_bucket_name

  lifecycle {
    prevent_destroy = true
  }
}

resource "aws_s3_bucket_public_access_block" "pipeline_artifacts" {
  bucket = aws_s3_bucket.pipeline_artifacts.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_s3_bucket_server_side_encryption_configuration" "pipeline_artifacts" {
  bucket = aws_s3_bucket.pipeline_artifacts.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm     = "aws:kms"
      kms_master_key_id = aws_kms_key.sagemaker_pipeline.arn
    }
  }
}

resource "aws_s3_bucket_versioning" "pipeline_artifacts" {
  bucket = aws_s3_bucket.pipeline_artifacts.id
  versioning_configuration {
    status = "Enabled"
  }
}

# IAM role for SageMaker Pipeline execution
resource "aws_iam_role" "pipeline_exec" {
  name = "sagemaker-pipeline-exec-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })
}

# Least‑privilege inline policy for the execution role
resource "aws_iam_role_policy" "pipeline_exec" {
  name = "sagemaker-pipeline-exec-policy"
  role = aws_iam_role.pipeline_exec.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "S3Access"
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.pipeline_artifacts.arn,
          "${aws_s3_bucket.pipeline_artifacts.arn}/*"
        ]
      },
      {
        Sid    = "KMSAccess"
        Effect = "Allow"
        Action = [
          "kms:GenerateDataKey",
          "kms:Decrypt"
        ]
        Resource = [aws_kms_key.sagemaker_pipeline.arn]
      },
      {
        Sid    = "SageMakerPipelineActions"
        Effect = "Allow"
        Action = [
          "sagemaker:CreatePipeline",
          "sagemaker:StartPipelineExecution",
          "sagemaker:StopPipelineExecution",
          "sagemaker:DescribePipeline",
          "sagemaker:ListPipelines",
          "sagemaker:DescribePipelineExecution",
          "sagemaker:ListPipelineExecutions"
        ]
        Resource = "*"
      },
      {
        Sid    = "SageMakerStepActions"
        Effect = "Allow"
        Action = [
          "sagemaker:CreateTrainingJob",
          "sagemaker:CreateModel",
          "sagemaker:CreateTransformJob",
          "sagemaker:CreateProcessingJob",
          "sagemaker:CreateAutoMLJob",
          "sagemaker:CreateHyperParameterTuningJob",
          "sagemaker:DescribeTrainingJob",
          "sagemaker:DescribeModel",
          "sagemaker:DescribeTransformJob",
          "sagemaker:DescribeProcessingJob",
          "sagemaker:DescribeAutoMLJob",
          "sagemaker:DescribeHyperParameterTuningJob",
          "sagemaker:AddTags",
          "sagemaker:ListTags"
        ]
        Resource = "*"
      },
      {
        Sid    = "PassRole"
        Effect = "Allow"
        Action = "iam:PassRole"
        Resource = aws_iam_role.pipeline_exec.arn
        Condition = {
          StringEquals = {
            "iam:PassedToService": "sagemaker.amazonaws.com"
          }
        }
      }
    ]
  })
}

# SageMaker Pipeline resource
resource "aws_sagemaker_pipeline" "main" {
  pipeline_name         = "my-sagemaker-pipeline"
  pipeline_display_name = "My-SageMaker-Pipeline"
  pipeline_description  = "Sample pipeline created by Terraform"
  pipeline_definition   = local.pipeline_definition
  role_arn              = aws_iam_role.pipeline_exec.arn
}

# Variables
variable "environment" {
  description = "Environment name"
  type        = string
  default     = "dev"
}

variable "model_name" {
  description = "Unique identifier for the SageMaker model"
  type        = string
  default     = "xgboost-model"
}

variable "xgboost_version" {
  description = "Version of XGBoost built-in algorithm"
  type        = string
  default     = "1.0-1"
}

# Data sources
data "aws_caller_identity" "current" {}
data "aws_region" "current" {}

# Local values
locals {
  common_tags = {
    Name        = var.model_name
    Environment = var.environment
    ManagedBy   = "Terraform"
  }
  # Build ECR image URI for built-in XGBoost
  ecr_image_uri = "${data.aws_caller_identity.current.account_id}.dkr.ecr.${data.aws_region.current.region}.amazonaws.com/sagemaker-xgboost:${var.xgboost_version}"

  # Model artifact bucket name - required for SageMaker model even with built-in
  model_bucket_name = "sagemaker-model-artifacts-${data.aws_caller_identity.current.account_id}-${data.aws_region.current.region}"
}

# KMS key for S3 bucket encryption
resource "aws_kms_key" "sagemaker_cmk" {
  description             = "Customer managed key for SageMaker model artifacts S3 bucket encryption"
  key_usage               = "ENCRYPT_DECRYPT"
  enable_key_rotation     = true
  deletion_window_in_days = 30

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "EnableRootAccess"
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action   = "kms:*"
        Resource = "*"
      }
    ]
  })

  tags = local.common_tags
}

resource "aws_kms_alias" "sagemaker_cmk" {
  name          = "alias/sagemaker-model-key"
  target_key_id = aws_kms_key.sagemaker_cmk.key_id
}

# S3 bucket for model artifacts
resource "aws_s3_bucket" "model_artifacts" {
  bucket = local.model_bucket_name

  tags = local.common_tags

  lifecycle {
    prevent_destroy = true
  }
}

resource "aws_s3_bucket_public_access_block" "model_artifacts" {
  bucket                  = aws_s3_bucket.model_artifacts.id
  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_s3_bucket_server_side_encryption_configuration" "model_artifacts" {
  bucket = aws_s3_bucket.model_artifacts.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm     = "aws:kms"
      kms_master_key_id = aws_kms_key.sagemaker_cmk.arn
    }
  }
}

# IAM role for SageMaker execution
resource "aws_iam_role" "sagemaker_execution" {
  name = "sagemaker-execution-role-${var.model_name}-${var.environment}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })

  tags = local.common_tags
}

# Least-privilege policy for SageMaker execution role
resource "aws_iam_role_policy" "sagemaker_execution" {
  name = "sagemaker-execution-policy-${var.model_name}-${var.environment}"
  role = aws_iam_role.sagemaker_execution.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "ecr:GetDownloadUrlForLayer",
          "ecr:BatchGetImage",
          "ecr:GetAuthorizationToken"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogStream",
          "logs:PutLogEvents",
          "logs:CreateLogGroup"
        ]
        Resource = "arn:aws:logs:${data.aws_region.current.region}:${data.aws_caller_identity.current.account_id}:log-group:/aws/sagemaker/*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:DeleteObject"
        ]
        Resource = "${aws_s3_bucket.model_artifacts.arn}/*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:ListBucket"
        ]
        Resource = aws_s3_bucket.model_artifacts.arn
      },
      {
        Effect = "Allow"
        Action = [
          "kms:Decrypt"
        ]
        Resource = aws_kms_key.sagemaker_cmk.arn
      }
    ]
  })
}

# SageMaker model
resource "aws_sagemaker_model" "this" {
  name               = var.model_name
  execution_role_arn = aws_iam_role.sagemaker_execution.arn

  primary_container {
    image = local.ecr_image_uri
  }

  tags = local.common_tags
}

# SageMaker endpoint configuration
resource "aws_sagemaker_endpoint_configuration" "this" {
  name = "${var.model_name}-config-${var.environment}"

  production_variants {
    variant_name           = "variant-1"
    model_name             = aws_sagemaker_model.this.name
    instance_type          = "ml.t2.medium"
    initial_instance_count = 1
  }

  tags = local.common_tags
}

terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    tls = {
      source  = "hashicorp/tls"
      version = "~> 4.0"
    }
  }
}

variable "ssh_cidr_blocks" {
  description = "CIDR blocks allowed to SSH into the instance"
  type        = list(string)
  default     = ["10.0.0.0/8"]
}

data "aws_availability_zones" "available" {
  state = "available"
}

data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }
}

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "main-vpc"
  }
}

resource "aws_subnet" "main" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  map_public_ip_on_launch = false
  availability_zone       = data.aws_availability_zones.available.names[0]

  tags = {
    Name = "main-subnet"
  }
}

resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw"
  }
}

resource "aws_route_table" "main" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }

  tags = {
    Name = "main-route-table"
  }
}

resource "aws_route_table_association" "main" {
  subnet_id      = aws_subnet.main.id
  route_table_id = aws_route_table.main.id
}

resource "aws_security_group" "main" {
  name        = "main-sg"
  description = "Security group for EC2 instance allowing SSH"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = var.ssh_cidr_blocks
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  tags = {
    Name = "main-sg"
  }
}

resource "tls_private_key" "main" {
  algorithm = "RSA"
  rsa_bits  = 4096
}

resource "aws_key_pair" "main" {
  key_name   = "main-key"
  public_key = tls_private_key.main.public_key_openssh
}

resource "aws_eip" "main" {
  domain = "vpc"
}

resource "aws_eip_association" "main" {
  instance_id   = aws_instance.main.id
  allocation_id = aws_eip.main.id
}

resource "aws_instance" "main" {
  ami                         = data.aws_ami.amazon_linux_2.id
  instance_type               = "t2.micro"
  subnet_id                   = aws_subnet.main.id
  vpc_security_group_ids      = [aws_security_group.main.id]
  key_name                    = aws_key_pair.main.key_name
  associate_public_ip_address = false

  metadata_options {
    http_tokens   = "required"
    http_endpoint = "enabled"
  }

  root_block_device {
    encrypted   = true
    volume_size = 8
  }

  tags = {
    Name = "main-instance"
  }
}

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.5"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

data "aws_availability_zones" "available" {
  state = "available"
}

locals {
  vpc_cidr = "10.0.0.0/16"
}

resource "aws_vpc" "main" {
  cidr_block           = local.vpc_cidr
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "elasticache-vpc"
  }
}

resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(local.vpc_cidr, 8, count.index)
  availability_zone = data.aws_availability_zones.available.names[count.index]
  tags = {
    Name = "elasticache-private-${count.index}"
  }
}

resource "aws_elasticache_subnet_group" "main" {
  name       = "redis-subnet-group"
  subnet_ids = aws_subnet.private[*].id
}

resource "aws_security_group" "redis" {
  name        = "redis-security-group"
  description = "Allow inbound Redis traffic from VPC CIDR"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 6379
    to_port     = 6379
    protocol    = "tcp"
    cidr_blocks = [local.vpc_cidr]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = [local.vpc_cidr]
  }

  tags = {
    Name = "redis-security-group"
  }
}

resource "aws_elasticache_parameter_group" "redis7" {
  name   = "redis7-params"
  family = "redis7"
}

resource "random_password" "auth_token" {
  length           = 16
  special          = true
  override_special = "!#$%&*()-_=+[]{}<>:?"
}

resource "aws_secretsmanager_secret" "redis_auth" {
  name = "ElastiCacheRedisAuthToken"
}

resource "aws_secretsmanager_secret_version" "redis_auth" {
  secret_id     = aws_secretsmanager_secret.redis_auth.id
  secret_string = random_password.auth_token.result
}

resource "aws_elasticache_replication_group" "redis" {
  replication_group_id          = "redis-cluster"
  description                   = "Redis cluster with AUTH"
  engine                        = "redis"
  engine_version                = "7.0"
  node_type                     = "cache.t3.micro"
  num_cache_clusters            = 1
  parameter_group_name          = aws_elasticache_parameter_group.redis7.name
  subnet_group_name             = aws_elasticache_subnet_group.main.name
  security_group_ids            = [aws_security_group.redis.id]
  port                          = 6379

  at_rest_encryption_enabled = true
  transit_encryption_enabled = true
  auth_token                 = random_password.auth_token.result

  tags = {
    Name = "redis-cluster"
  }

  lifecycle {
    prevent_destroy = true
  }
}

terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "elasticache-vpc"
  }
}

resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "elasticache-private-${count.index}"
  }
}

resource "aws_elasticache_subnet_group" "main" {
  name       = "elasticache-subnet-group"
  subnet_ids = aws_subnet.private[*].id
}

resource "aws_security_group" "main" {
  name        = "elasticache-sg"
  description = "Security group for ElastiCache Redis"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 6379
    to_port     = 6379
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  tags = {
    Name = "elasticache-sg"
  }
}

resource "aws_elasticache_parameter_group" "default" {
  family = "redis7"
  name   = "default-redis7-iam"

  parameter {
    name  = "cluster-enabled"
    value = "no"
  }
}

resource "aws_kms_key" "main" {
  description             = "KMS key for ElastiCache at-rest encryption"
  deletion_window_in_days = 7
  enable_key_rotation     = true

  tags = {
    Name = "elasticache-kms-key"
  }
}

# IAM role for applications that will connect using IAM authentication
resource "aws_iam_role" "main" {
  name = "elasticache-iam-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })

  tags = {
    Name = "elasticache-iam-role"
  }
}

# IAM policy to allow elasticache:Connect on the replication group
resource "aws_iam_policy" "main" {
  name        = "elasticache-connect-policy"
  description = "Allow elasticache:Connect on the specific replication group"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = "elasticache:Connect"
        Resource = aws_elasticache_replication_group.main.arn
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "main" {
  role       = aws_iam_role.main.name
  policy_arn = aws_iam_policy.main.arn
}

# ElastiCache user for IAM authentication (the application user)
resource "aws_elasticache_user" "main" {
  user_id    = "iam-user"
  user_name  = "iam-user"
  engine     = "redis"
  access_string = "on ~* +@all"

  authentication_mode {
    type = "iam"
  }

  tags = {
    Name = "elasticache-iam-user"
  }
}

# ElastiCache user named "default" required by AWS for user groups
resource "aws_elasticache_user" "default" {
  user_id    = "default-user"
  user_name  = "default"
  engine     = "redis"
  access_string = "on ~* +@all"

  authentication_mode {
    type = "iam"
  }

  tags = {
    Name = "elasticache-default-user"
  }
}

# User group that includes both the application user and the default user
resource "aws_elasticache_user_group" "main" {
  engine       = "redis"
  user_group_id = "iam-user-group"
  user_ids     = [aws_elasticache_user.main.user_id, aws_elasticache_user.default.user_id]

  tags = {
    Name = "elasticache-iam-user-group"
  }
}

# ElastiCache replication group
resource "aws_elasticache_replication_group" "main" {
  replication_group_id          = "demo-redis"
  description                   = "Redis replication group with IAM authentication"
  engine                        = "redis"
  engine_version                = "7.0"
  node_type                     = "cache.t3.micro"
  port                          = 6379
  parameter_group_name          = aws_elasticache_parameter_group.default.name
  subnet_group_name             = aws_elasticache_subnet_group.main.name
  security_group_ids            = [aws_security_group.main.id]
  num_cache_clusters            = 1
  multi_az_enabled              = false
  automatic_failover_enabled    = false
  at_rest_encryption_enabled    = true
  transit_encryption_enabled    = true
  kms_key_id                    = aws_kms_key.main.arn
  user_group_ids                = [aws_elasticache_user_group.main.id]

  lifecycle {
    prevent_destroy = true
  }

  tags = {
    Name = "demo-redis"
  }
}

terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

import {
  to = aws_elasticache_user.main
  id = "authuser"
}

resource "random_password" "elasticache_user" {
  length           = 32
  special          = true
  override_special = "!#$%&*()-_=+[]{}<>:?"
  min_lower        = 1
  min_upper        = 1
  min_numeric      = 1
  min_special      = 1
}

data "aws_availability_zones" "available" {
  state = "available"
}

locals {
  common_tags = {
    Environment = "dev"
    Project     = "elasticache-auth"
  }
}

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = merge(local.common_tags, {
    Name = "elasticache-auth-vpc"
  })
}

resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index + 1)
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = merge(local.common_tags, {
    Name = "elasticache-auth-private-${count.index}"
  })
}

resource "aws_security_group" "elasticache" {
  name        = "elasticache-auth-sg"
  description = "Security group for ElastiCache Redis"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "Allow Redis inbound from VPC"
    from_port   = 6379
    to_port     = 6379
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    description = "Allow outbound traffic within VPC"
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  tags = merge(local.common_tags, {
    Name = "elasticache-auth-sg"
  })
}

resource "aws_elasticache_subnet_group" "main" {
  name       = "elasticache-auth-subnet-group"
  subnet_ids = aws_subnet.private[*].id

  tags = local.common_tags
}

resource "aws_elasticache_parameter_group" "main" {
  name        = "elasticache-auth-params"
  family      = "redis7"
  description = "Parameter group with encryption enabled"

  parameter {
    name  = "at-rest-encryption-enabled"
    value = "yes"
  }

  parameter {
    name  = "transit-encryption-enabled"
    value = "yes"
  }

  tags = local.common_tags
}

resource "aws_secretsmanager_secret" "elasticache_password" {
  name                    = "elasticache-auth-user-password"
  description             = "Password for ElastiCache user authentication"
  recovery_window_in_days = 7

  lifecycle {
    prevent_destroy = true
  }

  tags = local.common_tags
}

resource "aws_secretsmanager_secret_version" "elasticache_password" {
  secret_id = aws_secretsmanager_secret.elasticache_password.id
  secret_string = jsonencode({
    password = random_password.elasticache_user.result
  })
}

resource "aws_elasticache_user" "main" {
  user_id       = "authuser"
  user_name     = "authuser"
  engine        = "redis"
  access_string = "on ~* &* +@all"

  passwords = [random_password.elasticache_user.result]

  lifecycle {
    prevent_destroy = true
  }

  tags = local.common_tags
}

resource "aws_elasticache_user" "default" {
  user_id             = "default"
  user_name           = "default"
  engine              = "redis"
  access_string       = "on ~* &* +@all"
  no_password_required = true

  tags = local.common_tags
}

resource "aws_elasticache_user_group" "main" {
  user_group_id = "authuser-group"
  engine        = "redis"
  user_ids      = [aws_elasticache_user.default.user_id, aws_elasticache_user.main.user_id]

  tags = local.common_tags
}

resource "aws_elasticache_replication_group" "main" {
  replication_group_id          = "elasticache-auth-rg"
  description                   = "ElastiCache replication group with user authentication"
  engine                        = "redis"
  engine_version                = "7.0"
  node_type                     = "cache.t3.micro"
  num_cache_clusters            = 1
  parameter_group_name          = aws_elasticache_parameter_group.main.name
  subnet_group_name             = aws_elasticache_subnet_group.main.name
  security_group_ids            = [aws_security_group.elasticache.id]
  automatic_failover_enabled    = false
  multi_az_enabled              = false
  at_rest_encryption_enabled    = true
  transit_encryption_enabled    = true
  user_group_ids                = [aws_elasticache_user_group.main.user_group_id]

  lifecycle {
    prevent_destroy = true
  }

  tags = local.common_tags
}

terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.5"
    }
  }
}

variable "environment" {
  description = "Environment name used for resource naming and tagging"
  type        = string
  default     = "dev"
}

locals {
  tags = {
    Environment = var.environment
  }

  # Define the three ElastiCache users with their friendly names
  users = {
    user1 = { user_name = "user-one" }
    user2 = { user_name = "user-two" }
    user3 = { user_name = "user-three" }
  }
}

# Generate a random password for each user
resource "random_password" "this" {
  for_each = local.users
  length   = 16
  special  = false
}

# Store each password in AWS Secrets Manager
resource "aws_secretsmanager_secret" "this" {
  for_each = local.users
  name     = "${var.environment}-elasticache-password-${each.key}"
  tags     = local.tags
}

resource "aws_secretsmanager_secret_version" "this" {
  for_each      = local.users
  secret_id     = aws_secretsmanager_secret.this[each.key].id
  secret_string = random_password.this[each.key].result
}

# Create the three ElastiCache users
resource "aws_elasticache_user" "this" {
  for_each       = local.users
  user_id        = each.key
  user_name      = each.value.user_name
  access_string  = "on ~* +@all"
  engine         = "REDIS"
  passwords      = [aws_secretsmanager_secret_version.this[each.key].secret_string]
  tags           = local.tags
}

# Create the ElastiCache user group containing all three users
resource "aws_elasticache_user_group" "main" {
  user_group_id = "${var.environment}-user-group"
  engine        = "REDIS"
  user_ids      = [for u in aws_elasticache_user.this : u.user_id]
  tags          = local.tags
}

terraform {
  required_version = "~> 1.5"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.5"
    }
  }
}

# Data source for available AZs
data "aws_availability_zones" "available" {
  state = "available"
}

# Random password for master user
resource "random_password" "master_password" {
  length           = 20
  special          = true
  override_special = "!#$%&*()-_=+[]{}<>:?"
}

# Secrets Manager secret and version for master credentials
resource "aws_secretsmanager_secret" "aurora_master" {
  name = "aurora-mysql-master-password"
}

resource "aws_secretsmanager_secret_version" "aurora_master" {
  secret_id     = aws_secretsmanager_secret.aurora_master.id
  secret_string = jsonencode({
    username = "admin"
    password = random_password.master_password.result
  })
}

# VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "aurora-mysql-vpc"
  }
}

# Subnets
resource "aws_subnet" "aurora_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = data.aws_availability_zones.available.names[0]

  tags = {
    Name = "aurora-mysql-subnet-1"
  }
}

resource "aws_subnet" "aurora_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = data.aws_availability_zones.available.names[1]

  tags = {
    Name = "aurora-mysql-subnet-2"
  }
}

# DB subnet group
resource "aws_db_subnet_group" "aurora" {
  name       = "aurora-mysql-subnet-group"
  subnet_ids = [aws_subnet.aurora_1.id, aws_subnet.aurora_2.id]

  tags = {
    Name = "aurora-mysql-subnet-group"
  }
}

# Security group
resource "aws_security_group" "aurora_mysql" {
  name        = "aurora-mysql-sg"
  description = "Security group for Aurora MySQL cluster"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  tags = {
    Name = "aurora-mysql-sg"
  }
}

# IAM role and policy for Enhanced Monitoring (kept for future use but not currently attached)
data "aws_iam_policy" "enhanced_monitoring" {
  name = "AmazonRDSEnhancedMonitoringRole"
}

resource "aws_iam_role" "rds_enhanced_monitoring" {
  name = "rds-enhanced-monitoring-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "monitoring.rds.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "enhanced_monitoring" {
  role       = aws_iam_role.rds_enhanced_monitoring.name
  policy_arn = data.aws_iam_policy.enhanced_monitoring.arn
}

# Aurora MySQL cluster - simplified for LocalStack compatibility
resource "aws_rds_cluster" "aurora" {
  cluster_identifier      = "aurora-mysql-cluster"
  engine                  = "aurora-mysql"
  engine_version          = "5.7.mysql_aurora.2.08.3"
  master_username         = "admin"
  master_password         = jsondecode(aws_secretsmanager_secret_version.aurora_master.secret_string)["password"]
  backup_retention_period = 0
  skip_final_snapshot     = true
  storage_encrypted       = true
  db_subnet_group_name    = aws_db_subnet_group.aurora.name
  vpc_security_group_ids  = [aws_security_group.aurora_mysql.id]

  lifecycle {
    prevent_destroy = true
  }

  tags = {
    Name = "aurora-mysql-cluster"
  }
}

# Aurora MySQL cluster instances
resource "aws_rds_cluster_instance" "aurora" {
  count              = 2
  identifier         = "aurora-mysql-instance-${count.index}"
  cluster_identifier = aws_rds_cluster.aurora.id
  instance_class     = "db.r5.large"
  engine             = aws_rds_cluster.aurora.engine
  engine_version     = aws_rds_cluster.aurora.engine_version
  promotion_tier     = count.index == 0 ? 0 : 1

  lifecycle {
    create_before_destroy = true
  }

  tags = {
    Name = "aurora-mysql-instance-${count.index}"
  }
}

terraform {
  required_version = ">= 1.3"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = ">= 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = ">= 3.0"
    }
  }
}

locals {
  name_prefix = "aurora-pg"
  db_master_username = "dbadmin"
  vpc_cidr = "10.0.0.0/16"
  subnet_cidrs = ["10.0.1.0/24", "10.0.2.0/24"]
}

data "aws_availability_zones" "available" {
  state = "available"
}

# VPC
resource "aws_vpc" "main" {
  cidr_block           = local.vpc_cidr
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "${local.name_prefix}-vpc"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id
  tags = {
    Name = "${local.name_prefix}-igw"
  }
}

# Route Table
resource "aws_route_table" "main" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
  tags = {
    Name = "${local.name_prefix}-rt"
  }
}

# Subnets
resource "aws_subnet" "main" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = local.subnet_cidrs[count.index]
  availability_zone = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false
  tags = {
    Name = "${local.name_prefix}-subnet-${count.index + 1}"
  }
}

# Route Table Associations
resource "aws_route_table_association" "main" {
  count          = 2
  subnet_id      = aws_subnet.main[count.index].id
  route_table_id = aws_route_table.main.id
}

# DB Subnet Group
resource "aws_db_subnet_group" "aurora" {
  name       = "${local.name_prefix}-db-subnet-group"
  subnet_ids = aws_subnet.main[*].id
  tags = {
    Name = "${local.name_prefix}-db-subnet-group"
  }
}

# Security Group
resource "aws_security_group" "aurora" {
  name        = "${local.name_prefix}-sg"
  description = "Security group for Aurora PostgreSQL cluster"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [local.vpc_cidr]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = [local.vpc_cidr]
  }

  tags = {
    Name = "${local.name_prefix}-sg"
  }
}

# Cluster Parameter Group
resource "aws_rds_cluster_parameter_group" "aurora" {
  name        = "${local.name_prefix}-cluster-param-group"
  family      = "aurora-postgresql15"
  description = "Cluster parameter group for Aurora PostgreSQL 15"

  parameter {
    name  = "rds.logical_replication"
    value = "1"
  }
}

# KMS Key for Aurora encryption
resource "aws_kms_key" "aurora" {
  description             = "KMS key for Aurora PostgreSQL cluster encryption"
  deletion_window_in_days = 7
  enable_key_rotation     = true
}

# Random Password
resource "random_password" "master" {
  length  = 20
  special = false
}

# Secrets Manager Secret
resource "aws_secretsmanager_secret" "aurora" {
  name = "${local.name_prefix}-master-secret"
  lifecycle {
    prevent_destroy = true
  }
  tags = {
    Name = "${local.name_prefix}-master-secret"
  }
}

resource "aws_secretsmanager_secret_version" "aurora" {
  secret_id = aws_secretsmanager_secret.aurora.id
  secret_string = jsonencode({
    username = local.db_master_username
    password = random_password.master.result
  })
}

# Aurora Cluster
resource "aws_rds_cluster" "aurora" {
  cluster_identifier     = "${local.name_prefix}-cluster"
  engine                 = "aurora-postgresql"
  engine_version         = "15.4"
  database_name          = null
  master_username        = local.db_master_username
  master_password        = random_password.master.result
  backup_retention_period = 7
  preferred_backup_window = "03:00-04:00"
  storage_encrypted       = true
  kms_key_id              = aws_kms_key.aurora.arn
  deletion_protection     = true
  db_subnet_group_name    = aws_db_subnet_group.aurora.name
  vpc_security_group_ids  = [aws_security_group.aurora.id]
  db_cluster_parameter_group_name = aws_rds_cluster_parameter_group.aurora.name
  skip_final_snapshot     = false
  final_snapshot_identifier = "${local.name_prefix}-cluster-final-snapshot"
  lifecycle {
    prevent_destroy = true
  }
  tags = {
    Name = "${local.name_prefix}-cluster"
  }
}

# Cluster Instances
resource "aws_rds_cluster_instance" "aurora" {
  count              = 2
  identifier         = "${local.name_prefix}-instance-${count.index + 1}"
  cluster_identifier = aws_rds_cluster.aurora.id
  instance_class     = "db.r6g.large"
  engine             = aws_rds_cluster.aurora.engine
  engine_version     = aws_rds_cluster.aurora.engine_version
  promotion_tier     = 0
  publicly_accessible = false
  db_subnet_group_name = aws_db_subnet_group.aurora.name
  tags = {
    Name = "${local.name_prefix}-instance-${count.index + 1}"
  }
}

# Outputs
output "cluster_endpoint" {
  value = aws_rds_cluster.aurora.endpoint
}

output "reader_endpoint" {
  value = aws_rds_cluster.aurora.reader_endpoint
}

output "secret_arn" {
  value = aws_secretsmanager_secret.aurora.arn
}

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
  required_version = ">= 1.0"
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "random_password" "master" {
  length           = 16
  special          = true
  lower            = true
  upper            = true
  numeric          = true
  override_special = "_-"
}

resource "aws_kms_key" "rds" {
  description             = "KMS key for RDS MySQL encryption"
  deletion_window_in_days = 10
  enable_key_rotation     = true
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "Enable IAM User Permissions"
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action   = "kms:*"
        Resource = "*"
      },
      {
        Sid    = "Allow RDS to use the key"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
        Action = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey"
        ]
        Resource = "*"
      }
    ]
  })
  lifecycle {
    prevent_destroy = true
  }
}

resource "aws_kms_alias" "rds" {
  name          = "alias/rds-mysql"
  target_key_id = aws_kms_key.rds.key_id
}

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "mysql-rds-vpc"
  }
}

resource "aws_subnet" "main" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false
  tags = {
    Name = "mysql-rds-subnet-${count.index}"
  }
}

resource "aws_db_subnet_group" "main" {
  name_prefix = "mysql-rds-"
  subnet_ids  = aws_subnet.main[*].id
  tags = {
    Name = "mysql-rds-subnet-group"
  }
}

resource "aws_security_group" "rds" {
  name        = "mysql-rds-sg"
  description = "Security group for MySQL RDS"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "MySQL access from within VPC"
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  tags = {
    Name = "mysql-rds-sg"
  }
}

resource "aws_db_parameter_group" "mysql" {
  name_prefix = "mysql8-0-"
  family      = "mysql8.0"
  parameter {
    name  = "character_set_server"
    value = "utf8mb4"
  }
  parameter {
    name  = "collation_server"
    value = "utf8mb4_general_ci"
  }
  tags = {
    Name = "mysql8-0-parameter-group"
  }
}

resource "aws_secretsmanager_secret" "db_password" {
  name        = "rds-mysql-master-password"
  description = "Master password for RDS MySQL instance"
}

resource "aws_secretsmanager_secret_version" "db_password" {
  secret_id     = aws_secretsmanager_secret.db_password.id
  secret_string = random_password.master.result
}

resource "aws_rds_cluster" "mysql" {
  cluster_identifier_prefix = "mysql-aurora-"
  engine                    = "aurora-mysql"
  engine_version            = "8.0.mysql_aurora.3.02.0"
  master_username           = "admin"
  master_password           = random_password.master.result
  backup_retention_period   = 1
  storage_encrypted         = true
  kms_key_id                = aws_kms_key.rds.arn
  db_subnet_group_name      = aws_db_subnet_group.main.name
  vpc_security_group_ids    = [aws_security_group.rds.id]
  skip_final_snapshot       = true

  lifecycle {
    prevent_destroy = true
  }

  tags = {
    Name = "mysql-aurora-cluster"
  }
}

resource "aws_rds_cluster_instance" "mysql" {
  identifier_prefix  = "mysql-aurora-"
  cluster_identifier = aws_rds_cluster.mysql.id
  instance_class     = "db.r5.large"
  engine             = aws_rds_cluster.mysql.engine
  engine_version     = aws_rds_cluster.mysql.engine_version

  tags = {
    Name = "mysql-aurora-instance"
  }
}

data "aws_caller_identity" "current" {}

terraform {
  required_version = ">= 1.3.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = ">= 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = ">= 3.0"
    }
  }
}

# Variable for RDS storage encryption (no default – pipeline must supply value)
variable "rds_storage_encrypted" {
  type        = bool
  description = "Enable RDS storage encryption. Set to true in production, false for LocalStack testing."
}

# Caller identity for key policy
data "aws_caller_identity" "current" {}

# VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "mysql-cluster-vpc"
  }
}

# Availability Zones (using data source to get available AZs)
data "aws_availability_zones" "available" {
  state = "available"
}

# Subnets – one per AZ, using first three available AZs (us-east-1a, us-east-1b, us-east-1c)
locals {
  azs = slice(data.aws_availability_zones.available.names, 0, 3)
}

resource "aws_subnet" "rds" {
  count                   = 3
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 4, count.index)
  availability_zone       = local.azs[count.index]
  map_public_ip_on_launch = false
  tags = {
    Name = "rds-subnet-${local.azs[count.index]}"
  }
}

# DB Subnet Group
resource "aws_db_subnet_group" "main" {
  name_prefix = "mysql-cluster-subnet-"
  subnet_ids  = aws_subnet.rds[*].id
  tags = {
    Name = "mysql-cluster-subnet-group"
  }
}

# Parameter Group for MySQL 8.0
resource "aws_db_parameter_group" "main" {
  name_prefix = "mysql8-cluster-params-"
  family      = "mysql8.0"
  tags = {
    Name = "mysql8-cluster-params"
  }
}

# Option Group for MySQL 8.0
resource "aws_db_option_group" "main" {
  name_prefix              = "mysql8-cluster-options-"
  engine_name              = "mysql"
  major_engine_version     = "8.0"
  option_group_description = "Default MySQL 8.0 option group"
  tags = {
    Name = "mysql8-cluster-options"
  }
}

# KMS Key Policy Document
data "aws_iam_policy_document" "rds_kms" {
  statement {
    sid    = "EnableRootAccess"
    effect = "Allow"
    principals {
      type        = "AWS"
      identifiers = ["arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"]
    }
    actions   = ["kms:*"]
    resources = ["*"]
  }
  statement {
    sid    = "AllowRDSEncryption"
    effect = "Allow"
    principals {
      type        = "Service"
      identifiers = ["rds.amazonaws.com"]
    }
    actions = [
      "kms:Encrypt",
      "kms:Decrypt",
      "kms:ReEncrypt*",
      "kms:GenerateDataKey*",
      "kms:DescribeKey"
    ]
    resources = ["*"]
  }
}

# KMS Key for RDS encryption (kept for future production use)
resource "aws_kms_key" "rds" {
  description             = "RDS encryption key for MySQL cluster"
  deletion_window_in_days = 7
  enable_key_rotation     = true
  policy                  = data.aws_iam_policy_document.rds_kms.json
  tags = {
    Name = "mysql-cluster-rds-key"
  }
}

resource "aws_kms_alias" "rds" {
  name          = "alias/rds-mysql-cluster-key"
  target_key_id = aws_kms_key.rds.id
}

# Security Group – allow MySQL access only from VPC CIDR
resource "aws_security_group" "rds" {
  name        = "mysql-cluster-sg"
  description = "Allow MySQL traffic from within VPC"
  vpc_id      = aws_vpc.main.id
  tags = {
    Name = "mysql-cluster-sg"
  }
}

resource "aws_security_group_rule" "mysql_inbound" {
  type              = "ingress"
  from_port         = 3306
  to_port           = 3306
  protocol          = "tcp"
  cidr_blocks       = [aws_vpc.main.cidr_block]
  security_group_id = aws_security_group.rds.id
}

resource "aws_security_group_rule" "all_outbound" {
  type              = "egress"
  from_port         = 0
  to_port           = 0
  protocol          = "-1"
  cidr_blocks       = [aws_vpc.main.cidr_block]
  security_group_id = aws_security_group.rds.id
}

# Secrets Manager – store the master password
resource "random_password" "master" {
  length  = 16
  special = false
}

resource "aws_secretsmanager_secret" "db_password" {
  name = "mysql-cluster-master-password"
  lifecycle {
    prevent_destroy = true
  }
  tags = {
    Name = "mysql-cluster-master-password"
  }
}

resource "aws_secretsmanager_secret_version" "db_password" {
  secret_id     = aws_secretsmanager_secret.db_password.id
  secret_string = random_password.master.result
}

# DB Instance (MySQL cluster with Multi-AZ)
resource "aws_db_instance" "main" {
  identifier_prefix = "mysql-cluster-"

  engine         = "mysql"
  engine_version = "8.0.28"
  instance_class = "db.t2.small"

  allocated_storage     = 100
  storage_encrypted     = var.rds_storage_encrypted
  storage_type          = "gp2"
  multi_az              = true
  publicly_accessible   = false
  skip_final_snapshot   = true # Set to false in production; using true for greenfield test
  backup_retention_period = 1

  db_subnet_group_name   = aws_db_subnet_group.main.name
  parameter_group_name   = aws_db_parameter_group.main.name
  option_group_name      = aws_db_option_group.main.name
  vpc_security_group_ids = [aws_security_group.rds.id]

  username = "admin"
  password = random_password.master.result

  lifecycle {
    prevent_destroy = true
  }

  tags = {
    Name = "mysql-cluster"
  }
}

terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

locals {
  name        = "my-sql-instance"
  environment = "dev"
  common_tags = {
    Name        = local.name
    Environment = local.environment
  }
}

data "aws_availability_zones" "available" {}

resource "random_password" "master" {
  length           = 16
  special          = true
  override_special = "_!#$%^*()-+="
}

resource "random_id" "db_suffix" {
  byte_length = 4
}

resource "aws_secretsmanager_secret" "master_password" {
  name = "${local.name}-master-password"
  tags = local.common_tags
}

resource "aws_secretsmanager_secret_version" "master_password" {
  secret_id     = aws_secretsmanager_secret.master_password.id
  secret_string = random_password.master.result
}

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  tags                 = local.common_tags
}

resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id
  tags   = local.common_tags
}

resource "aws_subnet" "public" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false
  tags = merge(local.common_tags, {
    Name = "${local.name}-public-${count.index}"
  })
}

resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index + 2)
  availability_zone = data.aws_availability_zones.available.names[count.index]
  tags = merge(local.common_tags, {
    Name = "${local.name}-private-${count.index}"
  })
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id
  tags   = local.common_tags
}

resource "aws_route" "public_internet" {
  route_table_id         = aws_route_table.public.id
  destination_cidr_block = "0.0.0.0/0"
  gateway_id             = aws_internet_gateway.main.id
}

resource "aws_route_table_association" "public" {
  count          = 2
  subnet_id      = aws_subnet.public[count.index].id
  route_table_id = aws_route_table.public.id
}

resource "aws_db_parameter_group" "main" {
  name_prefix = "${local.name}-param-group-"
  family      = "mysql8.0"
  tags        = local.common_tags
}

resource "aws_db_subnet_group" "main" {
  name_prefix = "${local.name}-subnet-group-"
  subnet_ids  = aws_subnet.private[*].id
  tags        = local.common_tags
}

resource "aws_security_group" "rds" {
  name        = "${local.name}-rds-sg"
  description = "Allow MySQL access from VPC"
  vpc_id      = aws_vpc.main.id
  tags        = local.common_tags
}

resource "aws_security_group_rule" "ingress_mysql" {
  type              = "ingress"
  from_port         = 3306
  to_port           = 3306
  protocol          = "tcp"
  cidr_blocks       = [aws_vpc.main.cidr_block]
  security_group_id = aws_security_group.rds.id
}

resource "aws_security_group_rule" "egress_all" {
  type              = "egress"
  from_port         = 0
  to_port           = 0
  protocol          = "-1"
  cidr_blocks       = [aws_vpc.main.cidr_block]
  security_group_id = aws_security_group.rds.id
}

resource "aws_db_instance" "main" {
  identifier            = "${local.name}-${random_id.db_suffix.hex}"
  engine                = "mysql"
  engine_version        = "8.0.35"
  instance_class        = "db.t2.micro"
  allocated_storage     = 20
  storage_type          = "gp2"
  backup_retention_period = 7
  username              = "admin"
  password              = random_password.master.result
  db_subnet_group_name  = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.rds.id]
  storage_encrypted     = true
  skip_final_snapshot   = false

  tags = local.common_tags

  lifecycle {
    prevent_destroy = true
  }
}

output "secret_arn" {
  value = aws_secretsmanager_secret.master_password.arn
}

# VPC for RDS
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "rds-vpc"
  }
}

# Data source for availability zones
data "aws_availability_zones" "available" {
  state = "available"
}

# Private subnets for RDS
resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "rds-private-subnet-${count.index}"
  }
}

# DB subnet group
resource "aws_db_subnet_group" "main" {
  name       = "rds-subnet-group"
  subnet_ids = aws_subnet.private[*].id

  tags = {
    Name = "rds-subnet-group"
  }
}

# Security group for RDS
resource "aws_security_group" "rds" {
  name        = "rds-postgres-sg"
  description = "Allow PostgreSQL inbound from VPC CIDR"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  tags = {
    Name = "rds-postgres-sg"
  }
}

# Random password for master user
resource "random_password" "master" {
  length           = 16
  special          = true
  override_special = "!#$%&*()-_=+[]{}<>?"
}

# Secrets Manager secret for master password
resource "aws_secretsmanager_secret" "db_password" {
  name                    = "rds-postgres-master-password"
  recovery_window_in_days = 0

  tags = {
    Name = "rds-postgres-master-password"
  }
}

resource "aws_secretsmanager_secret_version" "db_password" {
  secret_id     = aws_secretsmanager_secret.db_password.id
  secret_string = random_password.master.result
}

# DB parameter group with forced SSL and timezone
resource "aws_db_parameter_group" "postgres" {
  name        = "rds-postgres-params"
  family      = "postgres15"
  description = "Custom parameter group for PostgreSQL with forced SSL"

  parameter {
    name  = "rds.force_ssl"
    value = "1"
  }

  parameter {
    name  = "timezone"
    value = "UTC"
  }

  tags = {
    Name = "rds-postgres-params"
  }
}

# RDS PostgreSQL instance
resource "aws_db_instance" "postgres" {
  identifier             = "postgres-instance"
  engine                 = "postgres"
  engine_version         = "15.5"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  storage_type           = "gp3"
  storage_encrypted      = true

  db_name                = "mydb"
  username               = "dbadmin"
  password              = random_password.master.result

  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.rds.id]

  parameter_group_name   = aws_db_parameter_group.postgres.name

  backup_retention_period = 7
  backup_window           = "03:00-04:00"
  maintenance_window      = "sun:04:00-sun:05:00"

  skip_final_snapshot = true

  lifecycle {
    prevent_destroy = true
  }

  tags = {
    Name = "postgres-instance"
  }
}

# Outputs
output "db_endpoint" {
  description = "PostgreSQL database endpoint (address:port)"
  value       = "${aws_db_instance.postgres.address}:${aws_db_instance.postgres.port}"
}

output "secret_arn" {
  description = "ARN of the Secrets Manager secret containing the master password"
  value       = aws_secretsmanager_secret.db_password.arn
}

