provider "aws" {
  region = "us-east-1"
}

variable "environment" {
  description = "Deployment environment"
  type        = string
  default     = "dev"
}

data "aws_availability_zones" "available" {
  state = "available"
}

locals {
  name_prefix = "neptune-${var.environment}"
  common_tags = {
    Name        = local.name_prefix
    Environment = var.environment
    ManagedBy   = "Terraform"
  }
}

resource "random_id" "suffix" {
  byte_length = 4
}

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = local.common_tags
}

resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index + 1)
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = merge(local.common_tags, {
    Name = "${local.name_prefix}-private-subnet-${count.index + 1}"
  })
}

resource "aws_neptune_subnet_group" "neptune" {
  name_prefix = "${local.name_prefix}-"
  subnet_ids  = aws_subnet.private[*].id

  tags = local.common_tags
}

resource "aws_neptune_cluster_parameter_group" "custom" {
  family = "neptune1.3"
  name   = "${local.name_prefix}-param-group"

  parameter {
    name  = "neptune_enable_audit_log"
    value = "1"
  }

  tags = local.common_tags
}

resource "aws_kms_key" "neptune" {
  description             = "Neptune cluster encryption key"
  deletion_window_in_days = 7
  enable_key_rotation     = true

  tags = local.common_tags
}

resource "aws_kms_alias" "neptune" {
  name          = "alias/${local.name_prefix}-key"
  target_key_id = aws_kms_key.neptune.key_id
}

resource "aws_neptune_cluster" "main" {
  cluster_identifier                  = "${local.name_prefix}-cluster-${random_id.suffix.hex}"
  engine_version                      = "neptune1.3"
  storage_encrypted                   = true
  kms_key_arn                         = aws_kms_key.neptune.arn
  backup_retention_period             = 1
  final_snapshot_identifier           = "neptune-final-snapshot-${var.environment}"
  deletion_protection                 = false
  skip_final_snapshot                 = false
  vpc_security_group_ids              = [aws_security_group.neptune.id]
  neptune_cluster_parameter_group_name = aws_neptune_cluster_parameter_group.custom.name

  tags = local.common_tags

  lifecycle {
    prevent_destroy = true
  }
}

resource "aws_neptune_cluster_instance" "main" {
  cluster_identifier = aws_neptune_cluster.main.id
  identifier         = "${local.name_prefix}-instance"
  instance_class     = "db.r5.large"
  promotion_tier     = 0

  tags = local.common_tags
}

resource "aws_security_group" "neptune" {
  name        = "${local.name_prefix}-security-group"
  description = "Allow Neptune inbound traffic from VPC"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "Neptune HTTP"
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    description = "Allow outbound traffic within VPC"
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  tags = local.common_tags
}

terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.5"
    }
  }
}

