  cidr_block        = cidrsubnet(local.vpc_cidr, 8, count.index)
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "${local.name_prefix}-private-subnet-${count.index}"
  }
}

resource "aws_db_subnet_group" "neptune" {
  name       = "${local.name_prefix}-subnet-group"
  subnet_ids = aws_subnet.private[*].id

  tags = {
    Name = "${local.name_prefix}-subnet-group"
  }
}

resource "aws_security_group" "neptune" {
  name        = "${local.name_prefix}-sg"
  description = "Allow Neptune inbound from VPC"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = [local.vpc_cidr]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = [local.vpc_cidr]
  }

  tags = {
    Name = "${local.name_prefix}-sg"
  }
}

resource "aws_neptune_cluster_parameter_group" "cluster" {
  family      = "neptune1.2"
  name        = "${local.name_prefix}-cluster-params"
  description = "Custom cluster parameter group"

  parameter {
    name  = "neptune_enable_audit_log"
    value = "1"
  }
}

resource "random_password" "master" {
  length  = 20
  special = true
}

resource "aws_secretsmanager_secret" "master" {
  name = "${local.name_prefix}-master-password"
}

resource "aws_secretsmanager_secret_version" "master" {
  secret_id     = aws_secretsmanager_secret.master.id
  secret_string = random_password.master.result
}

resource "aws_kms_key" "neptune" {
  description             = "KMS key for Neptune cluster encryption"
  deletion_window_in_days = 7
  enable_key_rotation     = true
}

resource "aws_neptune_cluster" "main" {
  cluster_identifier                   = "${local.name_prefix}-cluster"
  engine                               = "neptune"
  engine_version                       = "1.2.0.0"
  vpc_security_group_ids               = [aws_security_group.neptune.id]
  kms_key_arn                          = aws_kms_key.neptune.arn
  skip_final_snapshot                  = true
  storage_encrypted                    = true
  backup_retention_period              = 1
  preferred_backup_window              = "03:00-04:00"
  preferred_maintenance_window         = "sun:04:00-sun:05:00"
  iam_database_authentication_enabled  = false

  lifecycle {
    prevent_destroy = true
  }

  tags = {
    Name = "${local.name_prefix}-cluster"
  }
}

resource "aws_neptune_parameter_group" "instance" {
  family      = "neptune1.2"
  name        = "${local.name_prefix}-instance-params"
  description = "Custom instance parameter group"

  parameter {
    name  = "neptune_query_timeout"
    value = "120000"
  }
}

resource "aws_neptune_cluster_instance" "main" {
  cluster_identifier               = aws_neptune_cluster.main.id
  identifier                       = "${local.name_prefix}-instance"
  instance_class                   = "db.r5.large"
  engine_version                   = "1.2.0.0"
  neptune_parameter_group_name     = aws_neptune_parameter_group.instance.name
  publicly_accessible              = false

  lifecycle {
    prevent_destroy = true
  }

  tags = {
    Name = "${local.name_prefix}-instance"
  }
}

