terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
    time = {
      source  = "hashicorp/time"
      version = "~> 0.9"
    }
  }
}

# Data source for availability zones
data "aws_availability_zones" "available" {
  state = "available"
}

# Data source for current AWS account ID (required for KMS key policy)
data "aws_caller_identity" "current" {}

# Random pet for master username and instance identifier
resource "random_pet" "db_master_username" {
  length = 2
}

# Random password for master password (16 characters with special characters)
resource "random_password" "db_master_password" {
  length           = 16
  special          = true
  override_special = "!#$%&*()-_=+[]{}<>:?"
}

# Secrets Manager secret to store credentials
resource "aws_secretsmanager_secret" "db_credentials" {
  name = "rds-master-credentials-${random_pet.db_master_username.id}"

  tags = {
    Name        = "rds-master-credentials-${random_pet.db_master_username.id}"
    Environment = "production"
  }

  lifecycle {
    prevent_destroy = true
  }
}

resource "aws_secretsmanager_secret_version" "db_credentials" {
  secret_id = aws_secretsmanager_secret.db_credentials.id
  secret_string = jsonencode({
    username = random_pet.db_master_username.id
    password = random_password.db_master_password.result
  })
}

# VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name        = "main-vpc"
    Environment = "production"
  }
}

# KMS key for RDS storage encryption with proper service policy
resource "aws_kms_key" "rds" {
  description             = "RDS Storage Encryption Key"
  deletion_window_in_days = 7
  enable_key_rotation     = true
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "Enable IAM User Permissions"
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action   = "kms:*"
        Resource = "*"
      },
      {
        Sid    = "Allow RDS Service to use the key"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
        Action = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey",
          "kms:CreateGrant"
        ]
        Resource = "*"
      }
    ]
  })

  tags = {
    Name        = "rds-storage-encryption-key"
    Environment = "production"
  }
}

# KMS alias for the RDS encryption key
resource "aws_kms_alias" "rds" {
  name          = "alias/rds-custom-${random_pet.db_master_username.id}"
  target_key_id = aws_kms_key.rds.id
}

# Time sleep to allow KMS key propagation before RDS creation
resource "time_sleep" "wait_for_kms_propagation" {
  depends_on      = [aws_kms_key.rds, aws_kms_alias.rds]
  create_duration = "30s"
}

# Private subnets (2 in different AZs)
resource "aws_subnet" "private" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = count.index == 0 ? "10.0.1.0/24" : "10.0.2.0/24"
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false

  tags = {
    Name        = "private-subnet-${count.index + 1}"
    Environment = "production"
  }
}

# DB subnet group
resource "aws_db_subnet_group" "main" {
  name       = "db-subnet-group-${random_pet.db_master_username.id}"
  subnet_ids = aws_subnet.private[*].id

  tags = {
    Name        = "db-subnet-group-${random_pet.db_master_username.id}"
    Environment = "production"
  }
}

# Security group for RDS
resource "aws_security_group" "rds" {
  name        = "rds-sg"
  description = "Security group for RDS instance"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  tags = {
    Name        = "rds-sg"
    Environment = "production"
  }

  lifecycle {
    prevent_destroy = true
  }
}

# RDS instance (PostgreSQL engine for better LocalStack compatibility with encryption)
resource "aws_db_instance" "main" {
  identifier             = "rds-${random_pet.db_master_username.id}"
  engine                 = "postgres"
  engine_version         = "15.4"
  instance_class         = "db.t2.micro"
  allocated_storage      = 20
  storage_encrypted      = true
  kms_key_id             = aws_kms_key.rds.arn
  username               = random_pet.db_master_username.id
  password               = random_password.db_master_password.result
  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.rds.id]
  skip_final_snapshot    = false
  backup_retention_period = 7
  publicly_accessible    = false
  multi_az               = false

  depends_on = [time_sleep.wait_for_kms_propagation]

  tags = {
    Name        = "rds-${random_pet.db_master_username.id}"
    Environment = "production"
  }

  lifecycle {
    prevent_destroy = true
  }
}

terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.6"
    }
  }
}

# Random resources for database credentials and identifier
resource "random_id" "db_identifier" {
  byte_length = 8
}

resource "random_pet" "master_username" {
  length    = 2
  separator = "_"
}

resource "random_password" "master_password" {
  length           = 20
  special          = false
  override_special = "!#$%^&*()-_=+[]{}<>:?"
}

# Data sources for static lookups
data "aws_availability_zones" "available" {
  state = "available"
}

# VPC and subnets
locals {
  vpc_cidr = "10.0.0.0/16"
}

resource "aws_vpc" "main" {
  cidr_block           = local.vpc_cidr
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "rds-vpc"
  }
}

resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(local.vpc_cidr, 8, count.index)
  availability_zone = data.aws_availability_zones.available.names[count.index]

  map_public_ip_on_launch = false

  tags = {
    Name = "rds-subnet-${count.index}"
  }
}

resource "aws_db_subnet_group" "main" {
  name       = "rds-subnet-group-${random_id.db_identifier.hex}"
  subnet_ids = aws_subnet.private[*].id

  tags = {
    Name = "rds-subnet-group"
  }
}

# Security group
resource "aws_security_group" "rds" {
  name        = "rds-mysql-${random_id.db_identifier.hex}"
  description = "Security group for MySQL RDS instance"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = [local.vpc_cidr]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = [local.vpc_cidr]
  }

  tags = {
    Name = "rds-mysql-sg"
  }
}

# Store secrets
resource "aws_secretsmanager_secret" "rds_credentials" {
  name = "rds-mysql-credentials-${random_id.db_identifier.hex}"

  lifecycle {
    prevent_destroy = true
  }
}

resource "aws_secretsmanager_secret_version" "rds_credentials" {
  secret_id = aws_secretsmanager_secret.rds_credentials.id
  secret_string = jsonencode({
    username = random_pet.master_username.id
    password = random_password.master_password.result
  })
}

# RDS MySQL instance
resource "aws_db_instance" "mysql" {
  identifier = "mysql-${random_id.db_identifier.hex}"

  engine         = "mysql"
  engine_version = "8.0.28"
  instance_class = "db.t2.micro"

  allocated_storage     = 20
  storage_type          = "gp2"
  storage_encrypted     = true

  username = random_pet.master_username.id
  password = random_password.master_password.result

  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.rds.id]

  backup_retention_period = 7

  skip_final_snapshot     = true
  deletion_protection     = true
  multi_az                = false

  lifecycle {
    prevent_destroy = true
  }

  tags = {
    Name = "mysql-instance"
  }
}

terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

resource "aws_db_option_group" "option_group_pike" {
  name                 = "option-group-pike"
  engine_name          = "sqlserver-ee"
  major_engine_version = "11.00"
}

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

resource "aws_db_option_group" "pike" {
  name                 = "option-group-pike"
  engine_name          = "sqlserver-ee"
  major_engine_version = "11.00"

  option {
    option_name = "SQLSERVER_AUDIT"
  }

  option {
    option_name = "TDE"
  }
}

terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = ">= 5.0"
    }
  }
}

locals {
  common_tags = {
    Name        = "pike-audit-infrastructure"
    Environment = "production"
    ManagedBy   = "terraform"
  }
}

# KMS customer managed key for S3 audit bucket encryption
resource "aws_kms_key" "audit_logs" {
  description             = "KMS CMK for S3 audit bucket encryption"
  deletion_window_in_days = 7
  enable_key_rotation     = true
  tags                    = local.common_tags
}

# S3 bucket for audit logs
resource "aws_s3_bucket" "audit_logs" {
  bucket        = "pike-audit-logs"
  force_destroy = false

  tags = merge(local.common_tags, {
    Name = "pike-audit-logs"
  })

  lifecycle {
    prevent_destroy = true
  }
}

resource "aws_s3_bucket_versioning" "audit_logs" {
  bucket = aws_s3_bucket.audit_logs.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "audit_logs" {
  bucket = aws_s3_bucket.audit_logs.id

  rule {
    apply_server_side_encryption_by_default {
      kms_master_key_id = aws_kms_key.audit_logs.arn
      sse_algorithm     = "aws:kms"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "audit_logs" {
  bucket = aws_s3_bucket.audit_logs.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_s3_bucket_lifecycle_configuration" "audit_logs" {
  bucket = aws_s3_bucket.audit_logs.id

  rule {
    id     = "transition-to-glacier-after-90-days"
    status = "Enabled"

    transition {
      days          = 90
      storage_class = "GLACIER"
    }

    noncurrent_version_transition {
      noncurrent_days = 90
      storage_class   = "GLACIER"
    }
  }
}

# IAM role for RDS audit
resource "aws_iam_role" "rds_audit_role" {
  name = "rds-audit-role-pike"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })

  tags = merge(local.common_tags, {
    Name = "rds-audit-role-pike"
  })
}

# IAM policy for S3 audit access
resource "aws_iam_policy" "audit_s3_policy" {
  name        = "rds-audit-s3-policy"
  description = "Permissions for RDS to write audit logs to S3 bucket"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.audit_logs.arn,
          "${aws_s3_bucket.audit_logs.arn}/*"
        ]
      }
    ]
  })

  tags = local.common_tags
}

resource "aws_iam_role_policy_attachment" "audit_s3_attach" {
  role       = aws_iam_role.rds_audit_role.name
  policy_arn = aws_iam_policy.audit_s3_policy.arn
}

# RDS option group
resource "aws_db_option_group" "option_group_pike" {
  name                     = "option-group-pike"
  engine_name              = "sqlserver-ee"
  major_engine_version     = "11.00"
  option_group_description = "Option group for SQL Server EE with audit and TDE"

  option {
    option_name = "SQLSERVER_AUDIT"

    option_settings {
      name  = "IAM_ROLE_ARN"
      value = aws_iam_role.rds_audit_role.arn
    }

    option_settings {
      name  = "S3_BUCKET_ARN"
      value = aws_s3_bucket.audit_logs.arn
    }
  }

  option {
    option_name = "TDE"
  }

  tags = merge(local.common_tags, {
    Name = "option-group-pike"
  })
}

terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = ">= 4.0"
    }
  }
}

locals {
  vault_name = "archive-vault"
}

# KMS key for SNS topic encryption
resource "aws_kms_key" "sns_encryption_key" {
  description             = "KMS key for SNS topic encryption"
  deletion_window_in_days = 7
  enable_key_rotation     = true

  lifecycle {
    prevent_destroy = true
  }
}

resource "aws_kms_alias" "sns_encryption_key_alias" {
  name          = "alias/sns-glacier-encryption-key"
  target_key_id = aws_kms_key.sns_encryption_key.key_id
}

# SNS topic for notifications with server-side encryption
resource "aws_sns_topic" "glacier_notifications" {
  name              = "glacier-archive-notifications"
  kms_master_key_id = aws_kms_key.sns_encryption_key.arn

  lifecycle {
    prevent_destroy = true
  }
}

# SNS topic policy to allow Glacier to publish
resource "aws_sns_topic_policy" "glacier_notifications_policy" {
  arn = aws_sns_topic.glacier_notifications.arn

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "AllowGlacierToPublish"
        Effect = "Allow"
        Principal = {
          Service = "glacier.amazonaws.com"
        }
        Action   = "SNS:Publish"
        Resource = aws_sns_topic.glacier_notifications.arn
      }
    ]
  })
}

# IAM policy document for vault access policy (least-privilege)
data "aws_iam_policy_document" "vault_policy" {
  statement {
    sid    = "RootAccess"
    effect = "Allow"
    principals {
      type        = "AWS"
      identifiers = ["arn:aws:iam::*:root"]
    }
    actions = [
      "glacier:InitiateJob",
      "glacier:UploadArchive",
      "glacier:AbortMultipartUpload",
      "glacier:CompleteMultipartUpload",
      "glacier:InitiateMultipartUpload",
      "glacier:ListParts",
      "glacier:UploadPart",
      "glacier:DeleteArchive",
      "glacier:DescribeJob",
      "glacier:GetJobOutput",
      "glacier:ListJobs",
    ]
    resources = ["arn:aws:glacier:*:*:vaults/${local.vault_name}"]
  }
}

# Glacier vault with inline notification (AWS-managed encryption by default)
resource "aws_glacier_vault" "archive_vault" {
  name = local.vault_name

  access_policy = data.aws_iam_policy_document.vault_policy.json

  notification {
    sns_topic = aws_sns_topic.glacier_notifications.arn
    events    = ["ArchiveRetrievalCompleted"]
  }

  lifecycle {
    prevent_destroy = true
  }
}

variable "environment" {
  description = "Environment name used for resource naming"
  type        = string
  default     = "production"
}

resource "random_id" "suffix" {
  byte_length = 4
}

data "aws_caller_identity" "current" {}

resource "aws_kms_key" "backup_key" {
  description             = "KMS key for long-term backup bucket encryption"
  deletion_window_in_days = 30
  enable_key_rotation     = true

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "EnableRootAdmin"
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action   = "kms:*"
        Resource = "*"
      },
      {
        Sid    = "AllowBackupServiceRoleToUseKey"
        Effect = "Allow"
        Principal = {
          AWS = aws_iam_role.backup_service_role.arn
        }
        Action = [
          "kms:Decrypt",
          "kms:Encrypt",
          "kms:GenerateDataKey",
          "kms:GenerateDataKeyWithoutPlaintext",
          "kms:ReEncryptFrom",
          "kms:ReEncryptTo",
          "kms:DescribeKey"
        ]
        Resource = "*"
      },
      {
        Sid    = "AllowS3ServiceToUseKey"
        Effect = "Allow"
        Principal = {
          Service = "s3.amazonaws.com"
        }
        Action = [
          "kms:Decrypt",
          "kms:GenerateDataKey",
          "kms:ReEncryptFrom",
          "kms:ReEncryptTo"
        ]
        Resource = "*"
      }
    ]
  })

  tags = {
    Name        = "${var.environment}-backup-key"
    Environment = var.environment
  }
}

resource "aws_s3_bucket" "long_term_backup" {
  bucket = "${var.environment}-long-term-backup-${random_id.suffix.hex}"

  lifecycle {
    prevent_destroy = true
  }

  tags = {
    Name        = "${var.environment}-long-term-backup"
    Environment = var.environment
  }
}

resource "aws_s3_bucket_versioning" "this" {
  bucket = aws_s3_bucket.long_term_backup.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "this" {
  bucket = aws_s3_bucket.long_term_backup.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm     = "aws:kms"
      kms_master_key_id = aws_kms_key.backup_key.arn
    }
  }
}

resource "aws_s3_bucket_public_access_block" "this" {
  bucket = aws_s3_bucket.long_term_backup.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_s3_bucket_lifecycle_configuration" "this" {
  bucket = aws_s3_bucket.long_term_backup.id

  rule {
    id     = "transition_to_standard_ia"
    status = "Enabled"

    filter {}

    transition {
      days          = 30
      storage_class = "STANDARD_IA"
    }
  }

  rule {
    id     = "transition_to_deep_archive"
    status = "Enabled"

    filter {}

    transition {
      days          = 90
      storage_class = "DEEP_ARCHIVE"
    }
  }

  rule {
    id     = "expire_noncurrent_versions"
    status = "Enabled"

    filter {}

    noncurrent_version_expiration {
      noncurrent_days = 365
    }
  }
}

data "aws_iam_policy_document" "backup_assume_role" {
  statement {
    effect  = "Allow"
    actions = ["sts:AssumeRole"]

    principals {
      type        = "Service"
      identifiers = ["backup.amazonaws.com"]
    }

    condition {
      test     = "StringEquals"
      variable = "aws:SourceAccount"
      values   = [data.aws_caller_identity.current.account_id]
    }
  }
}

resource "aws_iam_role" "backup_service_role" {
  name               = "backup-service-role-${var.environment}"
  assume_role_policy = data.aws_iam_policy_document.backup_assume_role.json

  tags = {
    Environment = var.environment
  }
}

data "aws_iam_policy_document" "backup_policy" {
  statement {
    effect = "Allow"
    actions = [
      "s3:PutObject",
      "s3:GetObject",
      "s3:ListBucket",
      "s3:DeleteObject"
    ]
    resources = [
      aws_s3_bucket.long_term_backup.arn,
      "${aws_s3_bucket.long_term_backup.arn}/*"
    ]
  }

  statement {
    effect = "Allow"
    actions = [
      "kms:Decrypt",
      "kms:Encrypt",
      "kms:GenerateDataKey",
      "kms:ReEncryptFrom",
      "kms:ReEncryptTo",
      "kms:DescribeKey"
    ]
    resources = [aws_kms_key.backup_key.arn]
  }
}

resource "aws_iam_policy" "backup_policy" {
  name        = "backup-s3-policy-${var.environment}"
  description = "Least-privilege policy for AWS Backup to access long-term backup bucket"
  policy      = data.aws_iam_policy_document.backup_policy.json
}

resource "aws_iam_role_policy_attachment" "backup_attach" {
  role       = aws_iam_role.backup_service_role.name
  policy_arn = aws_iam_policy.backup_policy.arn
}

terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

locals {
  vpc_cidr = "10.0.0.0/16"
  az_names = data.aws_availability_zones.available.names
  db_port  = 5432
}

# VPC
resource "aws_vpc" "main" {
  cidr_block           = local.vpc_cidr
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "terraform-sql-db-vpc"
  }
}

# Subnets (public for simplicity; production would use private subnets)
resource "aws_subnet" "public" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(local.vpc_cidr, 8, count.index)
  availability_zone = element(local.az_names, count.index)

  tags = {
    Name = "terraform-sql-db-subnet-${count.index}"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "terraform-sql-db-igw"
  }
}

# Route table for public subnets
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }

  tags = {
    Name = "terraform-sql-db-rt-public"
  }
}

# Associate subnets with route table
resource "aws_route_table_association" "public" {
  count          = 2
  subnet_id      = aws_subnet.public[count.index].id
  route_table_id = aws_route_table.public.id
}

# DB subnet group
resource "aws_db_subnet_group" "main" {
  name       = "terraform-sql-db-subnet-group"
  subnet_ids = aws_subnet.public[*].id

  tags = {
    Name = "terraform-sql-db-subnet-group"
  }
}

# Security group for RDS
resource "aws_security_group" "rds" {
  name        = "terraform-sql-db-sg"
  description = "Allow PostgreSQL inbound from VPC CIDR"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "PostgreSQL from VPC"
    from_port   = local.db_port
    to_port     = local.db_port
    protocol    = "tcp"
    cidr_blocks = [local.vpc_cidr]
  }

  egress {
    description = "Outbound within VPC only"
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = [local.vpc_cidr]
  }

  tags = {
    Name = "terraform-sql-db-sg"
  }
}

# Random password for database master
resource "random_password" "master" {
  length  = 16
  special = false
}

# Store password in AWS Secrets Manager
resource "aws_secretsmanager_secret" "db_password" {
  name = "terraform-sql-db-password"

  lifecycle {
    prevent_destroy = true
  }
}

